(function () {
  window.anatExtraExams = [
    {name:"CNS Anatomy",questions:[
      {id:"cns-001",difficulty:"Hard",topic:"Neural tube development",subtopic:"Neural plate and neural tube closure",question:"During early CNS development, which sequence correctly describes the formation and closure pattern of the neural tube?",options:{A:"The CNS begins as thickened ectoderm called the neural plate; neural folds elevate and fuse first in the cervical region, then closure proceeds cranially and caudally.",B:"The CNS begins from endoderm; the neural tube closes first at the caudal neuropore and then at the cranial neuropore.",C:"The neural tube forms by splitting of mesoderm; fusion begins at the cranial end and progresses only caudally.",D:"The neural tube forms from neural crest cells; cranial and caudal neuropores close simultaneously."},correct:"A",explanation:"The CNS originates from thickened ectoderm called the neural plate. Fusion begins in the cervical region and proceeds in both cephalic and caudal directions."},
      {id:"cns-002",difficulty:"Medium",topic:"Neural tube development",subtopic:"Neuropore closure",question:"Which statement correctly identifies the timing of cranial and caudal neuropore closure?",options:{A:"The cranial neuropore closes on day 21 and the caudal neuropore closes on day 25.",B:"Both neuropores close during the fourth month of development.",C:"The cranial neuropore closes on day 25 and the caudal neuropore closes on day 28.",D:"The caudal neuropore closes before the cranial neuropore."},correct:"C",explanation:"The cranial neuropore closes around day 25, while the caudal neuropore closes around day 28."},
      {id:"cns-003",difficulty:"Hard",topic:"Brain vesicles",subtopic:"Primary and secondary brain vesicles",question:"A student is asked to match the primary brain vesicles with their derivatives. Which pairing is correct?",options:{A:"Mesencephalon → telencephalon and diencephalon",B:"Rhombencephalon → myelencephalon and metencephalon",C:"Prosencephalon → medulla oblongata and pons",D:"Metencephalon → thalamus and hypothalamus"},correct:"B",explanation:"The rhombencephalon divides into the myelencephalon, which forms the medulla oblongata, and the metencephalon, which forms the pons and cerebellum."},
      {id:"cns-004",difficulty:"Hard",topic:"Spinal cord development",subtopic:"Mantle and marginal layers",question:"After neural tube closure, neuroepithelial cells differentiate and organize into layers. Which statement is correct?",options:{A:"The mantle layer forms white matter, while the marginal layer forms grey matter.",B:"The roof plate contains motor neurons, while the floor plate contains sensory neurons.",C:"The alar plate gives rise to motor neurons, and the basal plate gives rise to sensory neurons.",D:"The mantle layer forms grey matter, while the marginal layer contains nerve fibers that become white matter."},correct:"D",explanation:"Neuroblasts form the mantle layer, which becomes grey matter. The marginal layer contains nerve fibers and becomes white matter after myelination."},
      {id:"cns-005",difficulty:"Medium",topic:"Spinal cord development",subtopic:"Basal and alar plates",question:"Which embryological structure is primarily associated with motor neurons in the developing spinal cord?",options:{A:"Basal plate",B:"Alar plate",C:"Roof plate",D:"Neural crest-derived dorsal root ganglion"},correct:"A",explanation:"The basal plate is the ventral thickening of the developing spinal cord and contains motor neurons."},
      {id:"cns-006",difficulty:"Medium",topic:"Spinal cord anatomy",subtopic:"Conus medullaris and cauda equina",question:"In the adult, why can a lumbar puncture be safely performed below the L2 vertebral level?",options:{A:"The spinal cord continues to the coccyx, but the needle avoids it by passing anteriorly.",B:"The spinal cord usually terminates around L1-L2, while the subarachnoid space continues inferiorly to approximately S2.",C:"The cauda equina is covered only by dura mater and contains no nerve roots.",D:"The dural sac ends at L2, leaving only epidural fat below it."},correct:"B",explanation:"The adult spinal cord ends around L1-L2 as the conus medullaris, while the subarachnoid space extends to S2, making lower lumbar puncture safer."},
      {id:"cns-007",difficulty:"Medium",topic:"Spinal cord anatomy",subtopic:"Enlargements",question:"Which statement correctly describes the spinal cord enlargements?",options:{A:"The cervical enlargement corresponds to the sacral plexus, and the lumbar enlargement corresponds to the brachial plexus.",B:"Both enlargements are only embryological remnants and have no relation to limb innervation.",C:"The cervical enlargement lies at T11-L1 and the lumbar enlargement lies at C4-T1.",D:"The cervical enlargement is related to the brachial plexus, while the lumbar enlargement is related to lumbar and sacral plexuses."},correct:"D",explanation:"The cervical enlargement is located around C4-T1 and corresponds to the brachial plexus. The lumbar enlargement is around T11-L1 and relates to lumbar and sacral plexuses."},
      {id:"cns-008",difficulty:"Hard",topic:"Spinal meninges",subtopic:"Dura, arachnoid, pia",question:"Which description of the spinal meninges is most accurate?",options:{A:"The arachnoid mater is the innermost layer and forms denticulate ligaments.",B:"The dura mater is directly attached to the vertebral canal without an epidural space.",C:"The pia mater covers the spinal cord and thickens between nerve roots to form denticulate ligaments.",D:"The subarachnoid space lies between the dura mater and vertebral canal."},correct:"C",explanation:"The pia mater is the innermost meningeal layer and forms denticulate ligaments that help suspend the spinal cord."},
      {id:"cns-009",difficulty:"Medium",topic:"Spinal cord blood supply",subtopic:"Longitudinal arteries",question:"Which vessels form the main longitudinal arterial supply of the spinal cord?",options:{A:"One anterior spinal artery and paired posterior spinal arteries",B:"Paired anterior spinal arteries and one posterior spinal artery",C:"Only the basilar artery and its pontine branches",D:"Only the anterior cerebral arteries"},correct:"A",explanation:"The spinal cord is supplied by one anterior spinal artery and two posterior spinal arteries, supplemented by segmental medullary arteries."},
      {id:"cns-010",difficulty:"Hard",topic:"Spinal cord grey matter",subtopic:"Horns and columns",question:"Which spinal cord grey matter region is mainly associated with somatomotor neurons?",options:{A:"Posterior horn",B:"Intermediate column",C:"Central zone",D:"Anterior horn"},correct:"D",explanation:"The anterior horn contains somatomotor neurons and interneurons, while the posterior horn is mainly sensory."},
      {id:"cns-011",difficulty:"Hard",topic:"Spinal cord white matter",subtopic:"Posterior funiculus",question:"A lesion damages the fasciculus gracilis. Which sensory information is most directly affected?",options:{A:"Pain and temperature from the face",B:"Fine touch, vibration, and proprioception from the lower half of the body",C:"Crude touch from the upper limb only",D:"Motor control of facial muscles"},correct:"B",explanation:"The gracile fasciculus carries dorsal column sensory information from the lower half of the body. The cuneate fasciculus carries similar information from the upper body."},
      {id:"cns-012",difficulty:"Medium",topic:"Medulla oblongata",subtopic:"External anatomy",question:"Which structure on the anterior surface of the medulla contains descending corticospinal and corticobulbar fibers?",options:{A:"Olive",B:"Posterior median sulcus",C:"Pyramid",D:"Inferior cerebellar peduncle"},correct:"C",explanation:"The medullary pyramids are paired anterior swellings that contain descending corticospinal and corticobulbar fibers."},
      {id:"cns-013",difficulty:"Hard",topic:"Medulla oblongata",subtopic:"Cranial nerve exits",question:"Which cranial nerve exits from the ventrolateral sulcus of the medulla?",options:{A:"Hypoglossal nerve, CN XII",B:"Facial nerve, CN VII",C:"Trigeminal nerve, CN V",D:"Vestibulocochlear nerve, CN VIII"},correct:"A",explanation:"The hypoglossal nerve emerges from the ventrolateral sulcus of the medulla. CN IX, X, and XI are associated with the posterolateral sulcus."},
      {id:"cns-014",difficulty:"Hard",topic:"Medulla oblongata",subtopic:"Pyramidal decussation",question:"At the level of the pyramidal decussation, what major event occurs?",options:{A:"The medial lemniscus synapses in the thalamus.",B:"Auditory fibers decussate in the trapezoid body.",C:"The oculomotor nerve exits the midbrain.",D:"Most descending motor fibers cross to form the lateral corticospinal tract."},correct:"D",explanation:"At the pyramidal decussation, most corticospinal fibers cross and continue as the lateral corticospinal tract."},
      {id:"cns-015",difficulty:"Hard",topic:"Medulla oblongata",subtopic:"Medial lemniscus formation",question:"Which statement best explains how the medial lemniscus forms in the medulla?",options:{A:"Fibers from the inferior olive cross and form the medial lemniscus.",B:"Vestibular fibers from the semicircular canals enter the medulla and become the medial lemniscus.",C:"Internal arcuate fibers from the gracile and cuneate nuclei decussate and form the medial lemniscus.",D:"Fibers from the corticospinal tract synapse in the nucleus ambiguus and form the medial lemniscus."},correct:"C",explanation:"Second-order fibers from the gracile and cuneate nuclei cross as internal arcuate fibers and form the medial lemniscus."},
      {id:"cns-016",difficulty:"Hard",topic:"Medulla oblongata",subtopic:"Open medulla",question:"Which feature indicates that a medullary section is in the open medulla?",options:{A:"Presence of a closed central canal only",B:"Expansion of the central canal into the fourth ventricle",C:"Absence of cranial nerve nuclei",D:"Presence of the cerebral aqueduct"},correct:"B",explanation:"The medulla is considered open when the central canal opens into the fourth ventricle."},
      {id:"cns-017",difficulty:"Hard",topic:"Medulla oblongata",subtopic:"Nuclei",question:"Which nucleus provides motor fibers to cranial nerves IX, X, and XI?",options:{A:"Nucleus ambiguus",B:"Nucleus gracilis",C:"Medial vestibular nucleus",D:"Inferior olivary nucleus"},correct:"A",explanation:"The nucleus ambiguus provides motor fibers to cranial nerves IX, X, and XI."},
      {id:"cns-018",difficulty:"Medium",topic:"Pons",subtopic:"External anatomy",question:"Which external feature of the anterior pons is associated with the basilar artery?",options:{A:"Facial colliculus",B:"Stria medullaris",C:"Basilar groove",D:"Inferior fovea"},correct:"C",explanation:"The basilar groove is the midline groove on the anterior surface of the pons where the basilar artery lies."},
      {id:"cns-019",difficulty:"Hard",topic:"Pons",subtopic:"Internal anatomy",question:"Which structure is mainly responsible for transmitting pontine information to the cerebellum through the middle cerebellar peduncle?",options:{A:"Hypoglossal nucleus",B:"Inferior olivary nucleus",C:"Substantia nigra",D:"Pontine nuclei"},correct:"D",explanation:"The ventral pons contains pontine nuclei. Their fibers cross and form the middle cerebellar peduncles to reach the cerebellum."},
      {id:"cns-020",difficulty:"Hard",topic:"Pons",subtopic:"Facial colliculus",question:"The facial colliculus is formed mainly because fibers of which cranial nerve loop around which nucleus?",options:{A:"CN V around the trigeminal motor nucleus",B:"CN VII around the abducens nucleus",C:"CN VIII around the cochlear nucleus",D:"CN IX around the nucleus ambiguus"},correct:"B",explanation:"The facial colliculus is produced by facial nerve fibers looping around the abducens nucleus."},
      {id:"cns-021",difficulty:"Medium",topic:"Rhomboid fossa",subtopic:"Fourth ventricle floor",question:"The rhomboid fossa forms which anatomical surface?",options:{A:"The anterior floor of the fourth ventricle",B:"The roof of the third ventricle",C:"The lateral wall of the lateral ventricle",D:"The floor of the cerebral aqueduct"},correct:"A",explanation:"The rhomboid fossa is the diamond-shaped anterior floor of the fourth ventricle."},
      {id:"cns-022",difficulty:"Hard",topic:"Rhomboid fossa",subtopic:"Surface landmarks",question:"Which rhomboid fossa landmark overlies the hypoglossal nucleus?",options:{A:"Facial colliculus",B:"Vestibular area",C:"Locus caeruleus",D:"Hypoglossal trigone"},correct:"D",explanation:"The hypoglossal trigone corresponds to the underlying hypoglossal nucleus."},
      {id:"cns-023",difficulty:"Hard",topic:"Rhomboid fossa",subtopic:"Sulcus limitans",question:"What is the functional significance of the sulcus limitans in the rhomboid fossa?",options:{A:"It marks the exit of the trochlear nerve.",B:"It separates the cerebellar hemispheres.",C:"It forms the border between basal and alar plate derivatives.",D:"It connects the lateral ventricles to the third ventricle."},correct:"C",explanation:"The sulcus limitans separates medial motor/basal plate derivatives from lateral sensory/alar plate derivatives."},
      {id:"cns-024",difficulty:"Medium",topic:"Midbrain",subtopic:"External anatomy",question:"Which midbrain region is located posterior to the cerebral aqueduct and contains the colliculi?",options:{A:"Crus cerebri",B:"Tectum",C:"Substantia nigra",D:"Interpeduncular fossa"},correct:"B",explanation:"The tectum is posterior to the cerebral aqueduct and contains the superior and inferior colliculi."},
      {id:"cns-025",difficulty:"Hard",topic:"Midbrain",subtopic:"Cerebral peduncles",question:"Which structure divides the cerebral peduncle into the anterior crus cerebri and posterior tegmentum?",options:{A:"Substantia nigra",B:"Red nucleus",C:"Cerebral aqueduct",D:"Superior colliculus"},correct:"A",explanation:"The substantia nigra separates the anterior crus cerebri from the posterior tegmentum."},
      {id:"cns-026",difficulty:"Hard",topic:"Midbrain",subtopic:"Inferior colliculus level",question:"At the level of the inferior colliculus, which cranial nerve nucleus is found in the periaqueductal grey?",options:{A:"Oculomotor nucleus",B:"Abducens nucleus",C:"Trochlear nucleus",D:"Hypoglossal nucleus"},correct:"C",explanation:"At the inferior colliculus level, the trochlear nucleus is located in the periaqueductal grey."},
      {id:"cns-027",difficulty:"Hard",topic:"Midbrain",subtopic:"Superior colliculus level",question:"At the level of the superior colliculus, which structure replaces the trochlear nucleus?",options:{A:"Facial nucleus",B:"Nucleus ambiguus",C:"Dorsal motor nucleus of vagus",D:"Oculomotor nucleus"},correct:"D",explanation:"At the superior colliculus level, the oculomotor nucleus is present instead of the trochlear nucleus."},
      {id:"cns-028",difficulty:"Hard",topic:"Midbrain",subtopic:"Lemnisci",question:"Which lemniscus does not reach the superior colliculus level according to the notes?",options:{A:"Lateral lemniscus",B:"Medial lemniscus",C:"Spinal lemniscus",D:"Trigeminal lemniscus"},correct:"A",explanation:"At the superior colliculus level, the medial, spinal, and trigeminal lemnisci are present, but the lateral lemniscus does not reach this level."},
      {id:"cns-029",difficulty:"Hard",topic:"Reticular formation",subtopic:"Columns",question:"Which reticular formation column contains raphe nuclei and is strongly associated with serotonin release?",options:{A:"Lateral parvocellular zone",B:"Median column",C:"Medial gigantocellular zone",D:"Subthalamic column"},correct:"B",explanation:"The median column contains the raphe nuclei, which are involved in serotonin release, arousal, mood, and pain modulation."},
      {id:"cns-030",difficulty:"Hard",topic:"Reticular formation",subtopic:"Ascending reticular activation system",question:"Which function is most closely associated with the ascending reticular activation system?",options:{A:"Direct voluntary control of distal limb muscles only",B:"Transmission of visual information to the lateral geniculate body only",C:"Regulation of consciousness, arousal, and integration of sensory-autonomic information",D:"Formation of CSF in the choroid plexus"},correct:"C",explanation:"The ascending reticular activation system is important for consciousness, arousal, and integration of sensory/autonomic information."},
      {id:"cns-031",difficulty:"Medium",topic:"Cerebellum",subtopic:"Embryological origin",question:"The cerebellum develops from which secondary brain vesicle?",options:{A:"Telencephalon",B:"Diencephalon",C:"Myelencephalon",D:"Metencephalon"},correct:"D",explanation:"The metencephalon gives rise to the pons and cerebellum."},
      {id:"cns-032",difficulty:"Medium",topic:"Cerebellum",subtopic:"Cortex layers",question:"Which is the correct order of cerebellar cortex layers from superficial to deep?",options:{A:"Molecular layer → Purkinje layer → Granular layer",B:"Granular layer → Purkinje layer → Molecular layer",C:"Purkinje layer → Molecular layer → Granular layer",D:"Molecular layer → Granular layer → Purkinje layer"},correct:"A",explanation:"The cerebellar cortex consists of superficial molecular layer, middle Purkinje cell layer, and deep granular layer."},
      {id:"cns-033",difficulty:"Hard",topic:"Cerebellum",subtopic:"Functional divisions",question:"Which cerebellar functional division is mainly involved in balance and ocular reflexes?",options:{A:"Cerebrocerebellum",B:"Vestibulocerebellum",C:"Spinocerebellum",D:"Pontocerebellum"},correct:"B",explanation:"The vestibulocerebellum corresponds functionally to the flocculonodular lobe and is involved in balance and ocular reflexes."},
      {id:"cns-034",difficulty:"Hard",topic:"Cerebellum",subtopic:"Deep nuclei",question:"Which deep cerebellar nucleus is most lateral and receives afferents from the pontocerebellar system?",options:{A:"Fastigial nucleus",B:"Globose nucleus",C:"Dentate nucleus",D:"Emboliform nucleus"},correct:"C",explanation:"The dentate nucleus is the large lateral cerebellar nucleus and receives afferents from the pontocerebellar system."},
      {id:"cns-035",difficulty:"Hard",topic:"Cerebellar connections",subtopic:"Inferior cerebellar peduncle",question:"Which tract originates in the inferior olivary complex and terminates contralaterally as climbing fibers on Purkinje cells?",options:{A:"Posterior spinocerebellar tract",B:"Cuneocerebellar tract",C:"Pontocerebellar tract",D:"Olivocerebellar tract"},correct:"D",explanation:"The olivocerebellar tract arises from the inferior olivary complex and terminates contralaterally as climbing fibers on Purkinje cells."},
      {id:"cns-036",difficulty:"Medium",topic:"Cerebellar connections",subtopic:"Pontocerebellar tract",question:"The pontocerebellar tract reaches the cerebellum mainly through which cerebellar peduncle?",options:{A:"Middle cerebellar peduncle",B:"Inferior cerebellar peduncle",C:"Superior cerebellar peduncle",D:"No cerebellar peduncle; it enters through the thalamus"},correct:"A",explanation:"The pontocerebellar tract travels through the middle cerebellar peduncle and terminates as mossy fibers in the contralateral cerebellar hemisphere."},
      {id:"cns-037",difficulty:"Hard",topic:"Cerebellar cortex",subtopic:"Intrinsic neurons",question:"Which cerebellar cortical neuron is described as the only excitatory neuron in the cerebellar cortex?",options:{A:"Purkinje cell",B:"Granule cell",C:"Basket cell",D:"Golgi cell"},correct:"B",explanation:"Granule cells are the only excitatory neurons in the cerebellar cortex and use glutamate."},
      {id:"cns-038",difficulty:"Hard",topic:"Cerebellar cortex",subtopic:"Purkinje cells",question:"Which statement correctly describes Purkinje cells?",options:{A:"They are excitatory cells that use glutamate and project directly to the cerebral cortex.",B:"They are sensory first-order neurons in the dorsal root ganglion.",C:"They are inhibitory neurons whose axons project to cerebellar nuclei.",D:"They are located only in the pontine nuclei."},correct:"C",explanation:"Purkinje cells are inhibitory neurons; their axons run to deep cerebellar nuclei."},
      {id:"cns-039",difficulty:"Hard",topic:"Diencephalon",subtopic:"Borders",question:"Which structures form part of the floor of the diencephalon?",options:{A:"Tela choroidea and fornix",B:"Internal capsule and claustrum",C:"Pineal gland and posterior commissure",D:"Optic chiasm, infundibulum, and mammillary bodies"},correct:"D",explanation:"The floor of the diencephalon is formed by the optic chiasm, optic tract region, infundibulum, and mammillary bodies."},
      {id:"cns-040",difficulty:"Medium",topic:"Diencephalon",subtopic:"Major subdivisions",question:"Which list contains the four major subdivisions of the diencephalon?",options:{A:"Epithalamus, thalamus, subthalamus, hypothalamus",B:"Thalamus, pons, medulla, cerebellum",C:"Caudate nucleus, putamen, globus pallidus, claustrum",D:"Tectum, tegmentum, crus cerebri, substantia nigra"},correct:"A",explanation:"The diencephalon is divided into epithalamus, thalamus, subthalamus, and hypothalamus."},
      {id:"cns-041",difficulty:"Medium",topic:"Epithalamus",subtopic:"Pineal gland",question:"Which statement about the pineal gland is correct?",options:{A:"It secretes dopamine and controls voluntary movement.",B:"It secretes melatonin in response to darkness and is involved in circadian rhythm.",C:"It forms the lateral wall of the fourth ventricle.",D:"It receives optic radiation from the lateral geniculate body."},correct:"B",explanation:"The pineal gland contains pinealocytes that secrete melatonin in response to darkness and helps regulate circadian rhythm."},
      {id:"cns-042",difficulty:"Hard",topic:"Thalamus",subtopic:"External features",question:"Which thalamic external feature contains fibers from the amygdaloid body to the hypothalamus and runs with the superior thalamostriate vein?",options:{A:"Stria medullaris thalami",B:"Interthalamic adhesion",C:"Stria terminalis",D:"Lamina affixa"},correct:"C",explanation:"The stria terminalis carries fibers from the amygdala to hypothalamic/septal regions and runs with the superior thalamostriate vein."},
      {id:"cns-043",difficulty:"Hard",topic:"Thalamus",subtopic:"Functional nuclei",question:"Which thalamic nucleus is involved in the auditory pathway?",options:{A:"Lateral geniculate body",B:"Pulvinar",C:"Ventral posterolateral nucleus",D:"Medial geniculate body"},correct:"D",explanation:"The medial geniculate body is the thalamic relay nucleus for auditory information."},
      {id:"cns-044",difficulty:"Hard",topic:"Thalamus",subtopic:"Functional nuclei",question:"Which thalamic nucleus receives sensory input from the dorsal column-medial lemniscal pathway and anterolateral system of the body?",options:{A:"Ventral posterolateral nucleus",B:"Ventral posteromedial nucleus",C:"Anterior thalamic nucleus",D:"Medial geniculate body"},correct:"A",explanation:"The ventral posterolateral nucleus receives somatosensory information from the body, including DCML and spinothalamic inputs."},
      {id:"cns-045",difficulty:"Hard",topic:"Thalamus",subtopic:"Papez circuit",question:"Which thalamic nucleus is classically involved in the Papez circuit and episodic memory?",options:{A:"Pulvinar nucleus",B:"Anterior thalamic nucleus",C:"Ventral lateral nucleus",D:"Centromedian nucleus"},correct:"B",explanation:"The anterior thalamic nuclei participate in the Papez circuit, which is important for memory and emotional processing."},
      {id:"cns-046",difficulty:"Hard",topic:"Hypothalamus",subtopic:"Zones and nuclei",question:"Which group correctly belongs to the tuberal zone of the hypothalamus?",options:{A:"Supraoptic, paraventricular, suprachiasmatic",B:"Mammillary nuclei and posterior hypothalamic nucleus",C:"Arcuate nucleus, ventromedial nucleus, dorsomedial nucleus",D:"Lateral geniculate and medial geniculate nuclei"},correct:"C",explanation:"The tuberal zone includes the arcuate, ventromedial, and dorsomedial nuclei."},
      {id:"cns-047",difficulty:"Hard",topic:"Hypothalamus",subtopic:"Hunger and satiety",question:"Which hypothalamic nucleus is described as stimulating hunger through orexin release?",options:{A:"Ventromedial nucleus",B:"Suprachiasmatic nucleus",C:"Anterior hypothalamic nucleus",D:"Lateral hypothalamic nucleus"},correct:"D",explanation:"The lateral hypothalamic nucleus is associated with hunger and releases orexins."},
      {id:"cns-048",difficulty:"Hard",topic:"Hypothalamus",subtopic:"Neurohypophyseal regulation",question:"Which nuclei give rise to the hypothalamohypophyseal tract that projects to the posterior pituitary?",options:{A:"Supraoptic and paraventricular nuclei",B:"Anterior thalamic and dorsomedial nuclei",C:"Pulvinar and lateral geniculate nuclei",D:"Caudate and putamen"},correct:"A",explanation:"The hypothalamohypophyseal tract originates from neurosecretory cells in the supraoptic and paraventricular nuclei."},
      {id:"cns-049",difficulty:"Hard",topic:"Hypothalamohypophyseal system",subtopic:"Portal circulation",question:"Which structure forms the primary capillary plexus involved in hypothalamic regulation of the anterior pituitary?",options:{A:"Inferior hypophyseal artery",B:"Superior hypophyseal artery",C:"Anterior cerebral artery",D:"Posterior communicating artery"},correct:"B",explanation:"The superior hypophyseal artery forms the primary capillary plexus around the hypothalamus, which connects to the anterior pituitary through portal vessels."},
      {id:"cns-050",difficulty:"Hard",topic:"Basal ganglia",subtopic:"Components",question:"Which pair forms the striatum?",options:{A:"Globus pallidus internus and externus",B:"Subthalamic nucleus and substantia nigra",C:"Caudate nucleus and putamen",D:"Claustrum and external capsule"},correct:"C",explanation:"The striatum is formed by the caudate nucleus and putamen."},
      {id:"cns-051",difficulty:"Hard",topic:"Basal ganglia",subtopic:"Input and output nuclei",question:"Which basal ganglia components are output nuclei?",options:{A:"Caudate nucleus and putamen",B:"External globus pallidus and subthalamic nucleus",C:"Pars compacta of substantia nigra and caudate nucleus",D:"Internal globus pallidus and pars reticulata of substantia nigra"},correct:"D",explanation:"The main output nuclei are the internal globus pallidus and pars reticulata of the substantia nigra."},
      {id:"cns-052",difficulty:"Hard",topic:"Basal ganglia",subtopic:"Direct pathway",question:"What is the overall functional effect of the direct basal ganglia pathway?",options:{A:"It facilitates movement by reducing inhibitory output to the thalamus.",B:"It blocks all thalamic excitation to the motor cortex.",C:"It prevents dopamine release from the substantia nigra.",D:"It carries pain and temperature from the spinal cord."},correct:"A",explanation:"The direct pathway facilitates movement by inhibiting the output nuclei, thereby disinhibiting thalamic excitation of motor cortex."},
      {id:"cns-053",difficulty:"Hard",topic:"Basal ganglia",subtopic:"Indirect pathway",question:"What is the overall functional effect of the indirect basal ganglia pathway?",options:{A:"It excites the primary visual cortex.",B:"It inhibits movement by increasing inhibitory output to the thalamus.",C:"It carries proprioception from the lower limb to the cerebellum.",D:"It produces melatonin from the pineal gland."},correct:"B",explanation:"The indirect pathway increases inhibitory influence on the thalamus, thereby reducing motor cortical activation and suppressing movement."},
      {id:"cns-054",difficulty:"Hard",topic:"Basal ganglia",subtopic:"Parkinsonism",question:"Parkinsonism is primarily associated with degeneration of which neurons?",options:{A:"Serotonergic raphe neurons",B:"Cholinergic neurons of the neuromuscular junction",C:"Dopaminergic neurons of the substantia nigra",D:"Granule cells of the cerebellar cortex"},correct:"C",explanation:"Parkinsonism involves degeneration of dopaminergic neurons in the substantia nigra, impairing basal ganglia modulation of movement."},
      {id:"cns-055",difficulty:"Hard",topic:"Extrapyramidal tracts",subtopic:"Vestibulospinal tract",question:"Which statement best describes the vestibulospinal tracts?",options:{A:"They arise from the red nucleus and control fine hand movements.",B:"They begin in the superior colliculus and coordinate head movement to visual stimuli.",C:"They arise from the motor cortex and pass through the pyramids.",D:"They arise from vestibular nuclei and help control balance and posture through antigravity muscles."},correct:"D",explanation:"The vestibulospinal tracts arise from vestibular nuclei and influence balance and posture by acting on antigravity muscles."},
      {id:"cns-056",difficulty:"Medium",topic:"Extrapyramidal tracts",subtopic:"Tectospinal tract",question:"The tectospinal tract begins mainly from which structure?",options:{A:"Superior colliculus",B:"Inferior olive",C:"Ventral posterolateral nucleus",D:"Dentate nucleus"},correct:"A",explanation:"The tectospinal tract begins in the superior colliculus and coordinates head movements in response to visual stimuli."},
      {id:"cns-057",difficulty:"Hard",topic:"Cerebral cortex",subtopic:"Neocortex layers",question:"Which neocortical layer contains large pyramidal neurons, including Betz cells, and is dominant in motor cortex efferentation?",options:{A:"Layer I, molecular layer",B:"Layer V, internal pyramidal layer",C:"Layer IV, internal granular layer",D:"Layer II, external granular layer"},correct:"B",explanation:"Layer V contains large pyramidal neurons, including Betz cells, and is especially prominent in motor areas."},
      {id:"cns-058",difficulty:"Medium",topic:"Cerebral cortex",subtopic:"Primary motor cortex",question:"Where is the primary motor cortex located?",options:{A:"Postcentral gyrus",B:"Calcarine sulcus",C:"Precentral gyrus",D:"Superior temporal gyrus"},correct:"C",explanation:"The primary motor cortex is located in the precentral gyrus and corresponds to Brodmann area 4."},
      {id:"cns-059",difficulty:"Medium",topic:"Cerebral cortex",subtopic:"Primary somatosensory cortex",question:"The primary somatosensory cortex receives major thalamic input from which nuclei?",options:{A:"Anterior and dorsomedial nuclei",B:"Medial and lateral geniculate bodies",C:"Pulvinar and centromedian nuclei",D:"Ventral posterolateral and ventral posteromedial nuclei"},correct:"D",explanation:"The primary somatosensory cortex receives body and facial sensory information from VPL and VPM nuclei."},
      {id:"cns-060",difficulty:"Medium",topic:"Cerebral cortex",subtopic:"Visual cortex",question:"The primary visual cortex corresponds to which Brodmann area and location?",options:{A:"BA 17, calcarine sulcus",B:"BA 4, precentral gyrus",C:"BA 43, insular/opercular cortex",D:"BA 41/42, transverse temporal gyri"},correct:"A",explanation:"The primary visual cortex is Brodmann area 17 and is located around the calcarine sulcus."},
      {id:"cns-061",difficulty:"Hard",topic:"Cerebral cortex",subtopic:"Speech areas",question:"Which statement correctly describes Broca's area?",options:{A:"It is located in the calcarine sulcus and mediates primary visual perception.",B:"It is located in the inferior frontal gyrus and is important for speech production.",C:"It is located in the postcentral gyrus and mediates taste perception.",D:"It is located in the parahippocampal gyrus and processes smell."},correct:"B",explanation:"Broca's motor speech area is located in the inferior frontal gyrus and is important for speech production."},
      {id:"cns-062",difficulty:"Medium",topic:"Cerebral cortex",subtopic:"Auditory cortex",question:"The primary auditory cortex is located mainly in which structure?",options:{A:"Precentral gyrus",B:"Parahippocampal gyrus",C:"Transverse temporal gyri of Heschl",D:"Calcarine sulcus"},correct:"C",explanation:"The primary auditory cortex, Brodmann areas 41 and 42, is located in the transverse temporal gyri of Heschl."},
      {id:"cns-063",difficulty:"Medium",topic:"Cerebral cortex",subtopic:"Gustatory area",question:"The gustatory cortex is mainly located in which region?",options:{A:"Inferior frontal gyrus only",B:"Calcarine sulcus",C:"Cingulate gyrus",D:"Opercular part of the postcentral gyrus and adjacent insular cortex"},correct:"D",explanation:"The gustatory area, Brodmann area 43, is located in the opercular part of the postcentral gyrus and adjacent insular cortex."},
      {id:"cns-064",difficulty:"Hard",topic:"Cerebral white matter",subtopic:"Internal capsule",question:"Which statement about the internal capsule is correct?",options:{A:"It lies lateral to the thalamus and caudate nucleus and medial to the globus pallidus.",B:"It lies between the lentiform nucleus and claustrum and contains only association fibers.",C:"It is the commissural fiber bundle connecting both cerebellar hemispheres.",D:"It forms the roof of the third ventricle."},correct:"A",explanation:"The internal capsule lies lateral to the thalamus and caudate nucleus and medial to the globus pallidus."},
      {id:"cns-065",difficulty:"Hard",topic:"Cerebral white matter",subtopic:"Internal capsule parts",question:"Which tract is classically located in the genu of the internal capsule?",options:{A:"Optic radiation",B:"Corticonuclear tract",C:"Anterior thalamic radiation",D:"Acoustic radiation"},correct:"B",explanation:"The genu of the internal capsule contains corticonuclear fibers."},
      {id:"cns-066",difficulty:"Hard",topic:"Cerebral white matter",subtopic:"Association fibers",question:"Which association fiber tract connects Broca's area with Wernicke's area?",options:{A:"Cingulum",B:"Uncinate fasciculus",C:"Arcuate fasciculus",D:"Corpus callosum"},correct:"C",explanation:"The arcuate fasciculus connects Broca's and Wernicke's areas and is crucial for communication between motor and sensory speech regions."},
      {id:"cns-067",difficulty:"Medium",topic:"Cerebral white matter",subtopic:"Commissural fibers",question:"Which structure is the major commissural fiber bundle interconnecting neocortical gyri of both cerebral hemispheres?",options:{A:"Internal capsule",B:"Cingulum",C:"Corona radiata",D:"Corpus callosum"},correct:"D",explanation:"The corpus callosum is the major commissural bundle connecting the neocortical areas of both hemispheres."},
      {id:"cns-068",difficulty:"Hard",topic:"Ventricular system",subtopic:"CSF flow",question:"Which sequence correctly describes normal CSF flow from the lateral ventricles?",options:{A:"Lateral ventricles → interventricular foramina → third ventricle → cerebral aqueduct → fourth ventricle → median/lateral apertures or central canal",B:"Lateral ventricles → cerebral aqueduct → third ventricle → fourth ventricle → interventricular foramina",C:"Third ventricle → lateral ventricles → central canal → cerebral aqueduct",D:"Fourth ventricle → lateral ventricles → third ventricle → arachnoid granulations"},correct:"A",explanation:"CSF flows from lateral ventricles through the foramina of Monro to the third ventricle, then through the cerebral aqueduct to the fourth ventricle, then into the subarachnoid space or central canal."},
      {id:"cns-069",difficulty:"Hard",topic:"CSF",subtopic:"Production and absorption",question:"Where is CSF mainly produced and where is it reabsorbed?",options:{A:"Produced by arachnoid granulations and reabsorbed by the choroid plexus",B:"Produced by choroid plexus/ventricular ependyma and reabsorbed through arachnoid granulations",C:"Produced by the pituitary gland and reabsorbed through the pineal gland",D:"Produced by the internal capsule and reabsorbed in the basal ganglia"},correct:"B",explanation:"CSF is produced mainly by secretion from the choroid plexus and ventricular ependyma, and is reabsorbed through arachnoid granulations into dural venous sinuses."},
      {id:"cns-070",difficulty:"Hard",topic:"Hydrocephalus",subtopic:"Types",question:"Which statement best describes communicating hydrocephalus?",options:{A:"It is caused only by complete absence of CSF production.",B:"It occurs when the lateral ventricles are disconnected from the third ventricle.",C:"CSF reaches the subarachnoid space, but pressure is increased because absorption or balance is impaired.",D:"It always results from obstruction of the cerebral aqueduct."},correct:"C",explanation:"In communicating hydrocephalus, there is no block preventing CSF from reaching the subarachnoid space, but CSF pressure increases, often due to impaired absorption."},
      {id:"cns-071",difficulty:"Hard",topic:"Brain blood supply",subtopic:"Circle of Willis",question:"Which arteries form the main paired cerebral arteries of the Circle of Willis?",options:{A:"Ophthalmic, anterior choroidal, and superior cerebellar arteries",B:"Anterior spinal, posterior spinal, and pontine arteries",C:"Middle cerebral, basilar, and ophthalmic arteries",D:"Anterior cerebral, internal carotid, and posterior cerebral arteries"},correct:"D",explanation:"The circle includes paired anterior cerebral arteries, internal carotid arteries, and posterior cerebral arteries, connected by anterior and posterior communicating arteries."},
      {id:"cns-072",difficulty:"Medium",topic:"Brain blood supply",subtopic:"Internal carotid branches",question:"Which artery is a terminal branch of the internal carotid artery?",options:{A:"Middle cerebral artery",B:"Posterior inferior cerebellar artery",C:"Basilar artery",D:"Anterior spinal artery"},correct:"A",explanation:"The middle cerebral artery is one of the terminal branches of the internal carotid artery."},
      {id:"cns-073",difficulty:"Hard",topic:"Brain blood supply",subtopic:"Vertebral artery branches",question:"Which branch of the vertebral artery supplies the cerebellum according to the notes?",options:{A:"Middle cerebral artery",B:"Posterior inferior cerebellar artery",C:"Anterior cerebral artery",D:"Posterior communicating artery"},correct:"B",explanation:"The posterior inferior cerebellar artery arises from the vertebral artery and supplies the cerebellum."},
      {id:"cns-074",difficulty:"Hard",topic:"Brain blood supply",subtopic:"Cerebral artery territories",question:"A patient has contralateral weakness and sensory loss mainly affecting the face and arm, with aphasia if the dominant hemisphere is involved. Which artery is most likely occluded?",options:{A:"Anterior cerebral artery",B:"Posterior cerebral artery",C:"Middle cerebral artery",D:"Posterior inferior cerebellar artery"},correct:"C",explanation:"Middle cerebral artery occlusion typically affects the lateral cerebral hemisphere, causing contralateral face/arm weakness and sensory loss, and aphasia if the dominant hemisphere is affected."},
      {id:"cns-075",difficulty:"Hard",topic:"Blood-brain barrier",subtopic:"Structure",question:"Which components contribute directly to the structure of the blood-brain barrier?",options:{A:"Ependymal cilia, osteocytes, and chondrocytes",B:"Arachnoid granulations only",C:"Pinealocytes and Purkinje cells",D:"Capillary endothelial cells with tight junctions, basement membrane, astrocytic end-feet, and pericytes"},correct:"D",explanation:"The BBB is formed by specialized endothelial cells with tight junctions, supported by basement membrane, astrocytic end-feet, and pericytes."},
      {id:"cns-076",difficulty:"Hard",topic:"DCML pathway",subtopic:"First-order neurons",question:"Where are the first-order neurons of the dorsal column-medial lemniscal pathway located?",options:{A:"Ventral horn of spinal cord",B:"Dorsal root ganglia",C:"Ventral posterolateral nucleus of thalamus",D:"Primary somatosensory cortex"},correct:"B",explanation:"First-order DCML neurons are pseudounipolar neurons located in dorsal root ganglia."},
      {id:"cns-077",difficulty:"Hard",topic:"DCML pathway",subtopic:"Fasciculi",question:"Which statement correctly distinguishes gracile and cuneate fasciculi?",options:{A:"Gracile fasciculus carries lower body input below T6; cuneate fasciculus carries upper body input from T6 and above.",B:"Gracile fasciculus carries pain only; cuneate fasciculus carries temperature only.",C:"Cuneate fasciculus is medial; gracile fasciculus is lateral.",D:"Both fasciculi carry only motor information."},correct:"A",explanation:"Lower body information travels in the medial gracile fasciculus, while upper body information travels in the lateral cuneate fasciculus."},
      {id:"cns-078",difficulty:"Hard",topic:"DCML pathway",subtopic:"Lesions",question:"A lesion below the decussation of the DCML pathway will produce which sensory pattern?",options:{A:"Contralateral loss of pain and temperature only",B:"Bilateral loss of all motor function only",C:"Ipsilateral loss of smell",D:"Ipsilateral loss of fine touch, vibration, and proprioception below the lesion"},correct:"D",explanation:"Because DCML fibers decussate in the medulla, lesions below the decussation cause ipsilateral loss of fine touch, vibration, and proprioception."},
      {id:"cns-079",difficulty:"Hard",topic:"Anterolateral system",subtopic:"Spinothalamic tracts",question:"Which tract carries pain and temperature information?",options:{A:"Anterior spinothalamic tract",B:"Posterior spinocerebellar tract",C:"Lateral spinothalamic tract",D:"Corticospinal tract"},correct:"C",explanation:"The lateral spinothalamic tract carries pain and temperature sensation."},
      {id:"cns-080",difficulty:"Hard",topic:"Anterolateral system",subtopic:"Spinoreticular tract",question:"Which tract transmits slow pain and contributes to regulation of arousal through the reticular activation system?",options:{A:"Spinotectal tract",B:"Spinoreticular tract",C:"Dorsal column-medial lemniscal tract",D:"Anterior corticospinal tract"},correct:"B",explanation:"The spinoreticular tract transmits slow pain to the reticular formation and contributes to consciousness/arousal regulation."},
      {id:"cns-081",difficulty:"Hard",topic:"Anterolateral system",subtopic:"Spinotectal tract",question:"The spinotectal tract terminates mainly in which midbrain structure?",options:{A:"Superior colliculus",B:"Inferior olive",C:"Lateral geniculate body",D:"Red nucleus only"},correct:"A",explanation:"The spinotectal tract terminates in the superior colliculus and helps integrate tactile/proprioceptive information with visual reflexes."},
      {id:"cns-082",difficulty:"Hard",topic:"Pyramidal system",subtopic:"Corticospinal tract",question:"Which sequence correctly describes the corticospinal tract after it leaves the cerebral cortex?",options:{A:"Cortex → corpus callosum → lateral geniculate body → optic radiation",B:"Cortex → cerebellar cortex → dentate nucleus → spinal cord",C:"Cortex → dorsal root ganglion → posterior horn → thalamus",D:"Cortex → internal capsule → crus cerebri → pons → medulla → spinal cord"},correct:"D",explanation:"Corticospinal fibers descend through the internal capsule, crus cerebri, pons, medulla, and then into the spinal cord."},
      {id:"cns-083",difficulty:"Hard",topic:"Pyramidal system",subtopic:"Lateral corticospinal tract",question:"Which statement about the lateral corticospinal tract is correct?",options:{A:"It remains ipsilateral throughout the spinal cord and never decussates.",B:"It is responsible only for taste sensation.",C:"Its fibers decussate in the caudal medulla and descend in the spinal cord to influence lower motor neurons.",D:"It begins in the vestibular nuclei."},correct:"C",explanation:"Most corticospinal fibers cross in the pyramidal decussation and continue as the lateral corticospinal tract."},
      {id:"cns-084",difficulty:"Hard",topic:"Pyramidal system",subtopic:"Corticobulbar tract",question:"The corticobulbar tract primarily terminates on which structures?",options:{A:"Posterior horn sensory nuclei",B:"Motor nuclei of cranial nerves",C:"Choroid plexus epithelial cells",D:"Dorsal root ganglia"},correct:"B",explanation:"Corticobulbar fibers terminate on motor nuclei of cranial nerves to control muscles of the face and neck."},
      {id:"cns-085",difficulty:"Medium",topic:"Auditory pathway",subtopic:"First-order neurons",question:"Where are the first-order neurons of the auditory pathway located?",options:{A:"Spiral ganglion",B:"Geniculate ganglion",C:"Dorsal root ganglion",D:"Ventral posteromedial nucleus"},correct:"A",explanation:"First-order auditory neurons are bipolar neurons located in the spiral ganglion."},
      {id:"cns-086",difficulty:"Hard",topic:"Auditory pathway",subtopic:"Major relays",question:"Which relay sequence is most accurate for conscious auditory perception?",options:{A:"Retina → lateral geniculate body → calcarine cortex",B:"Taste buds → solitary nucleus → VPM → insula",C:"Olfactory epithelium → olfactory bulb → piriform cortex",D:"Spiral ganglion → cochlear nuclei → inferior colliculus → medial geniculate body → primary auditory cortex"},correct:"D",explanation:"The auditory pathway relays from spiral ganglion to cochlear nuclei, inferior colliculus, medial geniculate body, and then primary auditory cortex."},
      {id:"cns-087",difficulty:"Hard",topic:"Visual pathway",subtopic:"Retinal neurons",question:"Which sequence correctly identifies the first three neuronal levels of the visual pathway?",options:{A:"Ganglion cells → bipolar cells → rods and cones",B:"Bipolar cells → rods and cones → lateral geniculate body",C:"Rods/cones → bipolar neurons → retinal ganglion cells",D:"Lateral geniculate body → optic nerve → rods/cones"},correct:"C",explanation:"The visual pathway begins with photoreceptors, then bipolar neurons, then retinal ganglion cells whose axons form the optic nerve."},
      {id:"cns-088",difficulty:"Hard",topic:"Visual pathway",subtopic:"Optic radiation",question:"The axons of neurons in which structure form the optic radiation?",options:{A:"Medial geniculate body",B:"Lateral geniculate body",C:"Spiral ganglion",D:"Superior olivary nucleus"},correct:"B",explanation:"Fourth-order visual neurons are in the lateral geniculate body, and their axons form the optic radiation to the primary visual cortex."},
      {id:"cns-089",difficulty:"Hard",topic:"Olfactory pathway",subtopic:"Olfactory cortex",question:"Which set of structures is included in the olfactory cortex according to the notes?",options:{A:"Piriform cortex, amygdala, and entorhinal cortex",B:"Precentral gyrus, postcentral gyrus, and calcarine cortex",C:"Lateral geniculate body, medial geniculate body, and pulvinar",D:"Dentate nucleus, fastigial nucleus, and emboliform nucleus"},correct:"A",explanation:"The olfactory cortex includes the piriform cortex, amygdala, and entorhinal cortex."},
      {id:"cns-090",difficulty:"Hard",topic:"Gustatory pathway",subtopic:"Taste relays",question:"Taste fibers from the solitary nucleus ascend mainly to which thalamic nucleus?",options:{A:"Ventral posterolateral nucleus",B:"Lateral geniculate body",C:"Anterior thalamic nucleus",D:"Ventral posteromedial nucleus"},correct:"D",explanation:"Gustatory fibers from the solitary nucleus ascend to the ventral posteromedial nucleus of the thalamus before reaching the gustatory cortex."},
      {id:"cns-091",difficulty:"Medium",topic:"Limbic system",subtopic:"Main functions",question:"Which list best summarizes the main functions of the limbic system?",options:{A:"Voluntary movement only",B:"CSF production and reabsorption only",C:"Olfaction, memory, emotional responses, and behavior",D:"Visual acuity and pupillary constriction only"},correct:"C",explanation:"The limbic system is involved in olfaction, memory, emotional responses, and behavior."},
      {id:"cns-092",difficulty:"Hard",topic:"Limbic system",subtopic:"Hippocampal formation",question:"Which structure of the hippocampal formation is described as mainly afferent?",options:{A:"Subiculum",B:"Dentate gyrus",C:"Hippocampus proper",D:"Mammillary body"},correct:"B",explanation:"The dentate gyrus is described as the afferent part of the hippocampal formation."},
      {id:"cns-093",difficulty:"Hard",topic:"Limbic system",subtopic:"Fornix",question:"Which connection is made by the fornix?",options:{A:"Hippocampus with septal area and mammillary bodies",B:"Broca area with Wernicke area",C:"Cochlear nuclei with inferior colliculus",D:"Visual cortex with lateral geniculate body"},correct:"A",explanation:"The fornix connects the hippocampus with the septal area and mammillary bodies."},
      {id:"cns-094",difficulty:"Hard",topic:"Limbic system",subtopic:"Papez circuit",question:"Which sequence best represents the Papez circuit described in the notes?",options:{A:"Amygdala → lateral geniculate body → visual cortex → Broca area",B:"Taste buds → solitary nucleus → VPM → insular cortex",C:"Spiral ganglion → cochlear nuclei → inferior colliculus → auditory cortex",D:"Hippocampus → mammillary bodies → anterior thalamic nuclei → cingulate gyrus → entorhinal cortex → hippocampus"},correct:"D",explanation:"The Papez circuit links hippocampus, mammillary bodies, anterior thalamic nuclei, cingulate gyrus, entorhinal cortex, and back to hippocampus."},
      {id:"cns-095",difficulty:"Hard",topic:"Limbic system",subtopic:"Amygdala pathways",question:"Which white matter pathways connect the amygdala with hypothalamic and septal regions?",options:{A:"Optic radiation and acoustic radiation",B:"Corticospinal and corticobulbar tracts",C:"Stria terminalis and ventral amygdalofugal pathway",D:"Anterior and posterior spinocerebellar tracts"},correct:"C",explanation:"The stria terminalis and ventral amygdalofugal pathway connect the amygdala with septal, hypothalamic, and related limbic regions."},
      {id:"cns-096",difficulty:"Medium",topic:"Neurotransmitters",subtopic:"Classification",question:"Which neurotransmitter is described as the main excitatory neurotransmitter in the CNS?",options:{A:"GABA",B:"Glutamate",C:"Glycine",D:"Serotonin"},correct:"B",explanation:"Glutamate is the main excitatory neurotransmitter in the CNS."},
      {id:"cns-097",difficulty:"Medium",topic:"Neurotransmitters",subtopic:"GABA",question:"Which statement about GABA is correct?",options:{A:"It is inhibitory within the CNS and is involved in basal ganglia circuitry.",B:"It is produced by the pineal gland and controls circadian rhythm.",C:"It is the main excitatory neurotransmitter released by the subthalamic nucleus.",D:"It is found only at the neuromuscular junction."},correct:"A",explanation:"GABA is the main inhibitory neurotransmitter in the CNS and is important in basal ganglia circuits."},
      {id:"cns-098",difficulty:"Medium",topic:"Neurotransmitters",subtopic:"Serotonin",question:"Serotonin is primarily produced in which nuclei according to the notes?",options:{A:"Dentate nuclei",B:"Anterior thalamic nuclei",C:"Subthalamic nuclei",D:"Raphe nuclei"},correct:"D",explanation:"Serotonin is primarily produced in the raphe nuclei of the reticular formation."},
      {id:"cns-099",difficulty:"Hard",topic:"Spinal nerve",subtopic:"Dorsal root ganglion",question:"Which statement best describes dorsal root ganglion neurons?",options:{A:"They are multipolar motor neurons located in the anterior horn.",B:"They are glial cells that form the blood-brain barrier.",C:"They are pseudounipolar sensory neurons conveying information from receptors to the spinal cord.",D:"They are inhibitory interneurons located only in the cerebellar cortex."},correct:"C",explanation:"Dorsal root ganglia contain pseudounipolar sensory neurons that transmit sensory information from peripheral receptors into the spinal cord."},
      {id:"cns-100",difficulty:"Hard",topic:"Integrated CNS anatomy",subtopic:"Clinical localization",question:"A lesion causes loss of pain and temperature sensation on the contralateral side of the body, while dorsal column modalities below the lesion are preserved. Which tract is most likely affected?",options:{A:"Fasciculus gracilis",B:"Lateral spinothalamic tract",C:"Corticobulbar tract",D:"Posterior spinocerebellar tract"},correct:"B",explanation:"The lateral spinothalamic tract carries pain and temperature. Because these fibers decussate in the spinal cord, lesions typically cause contralateral pain and temperature loss."},
    ]},
    {name:"Embryology",questions:[
      {id:"emb-001",difficulty:"Easy",topic:"Development of the skull",subtopic:"Embryonic origin and ossification",question:"Which statement best describes the general embryonic origin and ossification patterns of the skull?",options:{A:"The entire skull is derived only from paraxial mesoderm and develops exclusively by endochondral ossification.",B:"The skull is derived only from neural crest cells, and all cranial bones ossify through intramembranous ossification.",C:"The skull develops from neural crest cells and mesodermal sources, and its bones form through both intramembranous and endochondral ossification.",D:"The skull develops from endodermal pharyngeal pouches, and its bones form through direct epithelial transformation."},correct:"C",explanation:"The skeletal system, including the skull, is derived from paraxial mesoderm, lateral plate mesoderm, and neural crest cells. Skull bones form by either intramembranous or endochondral ossification."},
      {id:"emb-002",difficulty:"Medium",topic:"Development of the skull",subtopic:"Viscerocranium",question:"The maxillary process of the first pharyngeal arch contributes to the formation of several facial bones. Which option correctly identifies bones derived from this process?",options:{A:"Maxilla, zygomatic bone, palatine bone, lacrimal bone, nasal bone, vomer, temporal bone contribution, and inferior nasal concha",B:"Mandible, malleus, incus, sphenomandibular ligament, and the styloid process of the temporal bone",C:"Stapes, styloid process, hyoid bone, stylohyoid ligament, and the mastoid part of the temporal bone",D:"Parietal bone, intraparietal occipital bone, frontal bone, and squamous temporal bone"},correct:"A",explanation:"The maxillary process gives rise to multiple facial bones, including the maxilla, zygomatic bone, palatine bone, lacrimal bone, nasal bone, vomer, temporal bone contribution, and inferior nasal concha."},
      {id:"emb-003",difficulty:"Medium",topic:"Development of the skull",subtopic:"Pharyngeal arch derivatives",question:"Which structure is derived from the mandibular process of the first pharyngeal arch?",options:{A:"Stapes and styloid process of the temporal bone",B:"Hyoid bone and stylohyoid ligament",C:"Frontal bone and squamous temporal bone",D:"Mandible, sphenomandibular ligament, malleus, and incus"},correct:"D",explanation:"The mandibular process of the first pharyngeal arch gives rise to the mandible, sphenomandibular ligament, malleus, and incus."},
      {id:"emb-004",difficulty:"Hard",topic:"Development of the skull",subtopic:"Neurocranium",question:"Which statement correctly distinguishes membranous and cartilaginous neurocranium development?",options:{A:"The membranous neurocranium forms the skull base by endochondral ossification, while the cartilaginous neurocranium forms the skull roof by intramembranous ossification.",B:"The membranous neurocranium forms much of the roof and lateral walls by intramembranous ossification, while the cartilaginous neurocranium forms skull base elements by endochondral ossification.",C:"Both membranous and cartilaginous neurocranium are derived only from endoderm and form only by intramembranous ossification.",D:"The cartilaginous neurocranium forms only the frontal and parietal bones, while the membranous neurocranium forms the ethmoid and sphenoid bones."},correct:"B",explanation:"The membranous neurocranium forms the roof and lateral walls of the skull by intramembranous ossification. The cartilaginous neurocranium forms skull base structures by endochondral ossification."},
      {id:"emb-005",difficulty:"Medium",topic:"Skull defects",subtopic:"Cranioschisis and craniosynostosis",question:"Cranioschisis is best explained by which developmental failure?",options:{A:"Failure of the cranial neuropore to close, leading to absence of cranial roof formation and degeneration of exposed brain tissue",B:"Premature closure of one or more cranial sutures, causing abnormal skull shape but survival in most cases",C:"Failure of the mandibular process to fuse with the maxillary process, causing facial clefting",D:"Failure of endochondral ossification in the sphenoid bone, causing isolated skull base shortening"},correct:"A",explanation:"Cranioschisis results from failure of cranial neuropore closure. The cranial roof fails to form, exposing brain tissue to amniotic fluid and leading to anencephaly."},
      {id:"emb-006",difficulty:"Medium",topic:"Vertebral column development",subtopic:"Sclerotome and resegmentation",question:"Which sequence correctly describes the developmental basis of vertebral body formation?",options:{A:"Dermatome cells migrate laterally, fuse with limb mesenchyme, and directly form vertebral bodies.",B:"Neural crest cells migrate around the notochord and form vertebrae without segmentation.",C:"Lateral plate mesoderm forms paired sternal bands that later segment into vertebrae.",D:"Sclerotome cells migrate medially toward the notochord, merge with opposite-side cells, and resegment so each vertebra contains parts of two adjacent somites."},correct:"D",explanation:"Vertebrae arise from sclerotome portions of somites. During resegmentation, the caudal half of one sclerotome fuses with the cranial half of the subjacent sclerotome."},
      {id:"emb-007",difficulty:"Easy",topic:"Vertebral column development",subtopic:"Intervertebral disc",question:"Which structure is formed by the persistent notochord within the intervertebral disc region?",options:{A:"Annulus fibrosus",B:"Vertebral arch",C:"Nucleus pulposus",D:"Posterior longitudinal ligament"},correct:"C",explanation:"The notochord regresses in the vertebral body region but persists and enlarges in the intervertebral disc region to form the nucleus pulposus."},
      {id:"emb-008",difficulty:"Hard",topic:"Vertebral defects",subtopic:"Spina bifida",question:"Which option best distinguishes spina bifida occulta from spina bifida cystica?",options:{A:"Spina bifida occulta involves complete absence of the spinal cord, while cystica affects only the skin.",B:"Spina bifida occulta involves small vertebral arch fusion defects without spinal cord protrusion, while cystica involves failure of neural tube closure with exposed spinal cord structures.",C:"Spina bifida occulta results from abnormal limb rotation, while cystica results from failure of sternal band fusion.",D:"Spina bifida occulta affects only cervical vertebrae, while cystica affects only lumbar ribs."},correct:"B",explanation:"Spina bifida occulta is a mild defect where vertebral arches fail to fuse but the spinal cord does not protrude. Spina bifida cystica is more severe and involves neural tube closure failure with exposed neural structures."},
      {id:"emb-009",difficulty:"Medium",topic:"Development of ribs and sternum",subtopic:"Sternum development",question:"The sternum develops from which embryonic structure and germ-layer derivative?",options:{A:"Sclerotome cells of thoracic somites that grow from costal processes",B:"Neural crest cells from the first and second pharyngeal arches",C:"Two sternal bands in the parietal layer of the lateral plate mesoderm that fuse in the midline",D:"Endodermal cells of the ventral foregut that ossify directly"},correct:"C",explanation:"The sternum develops independently in the ventral body wall from two sternal bands in the parietal layer of the lateral plate mesoderm, which fuse to form the cartilaginous model."},
      {id:"emb-010",difficulty:"Medium",topic:"Development of ribs and sternum",subtopic:"Rib defects",question:"A cervical rib arising near C7 may produce symptoms mainly because it can compress which structures?",options:{A:"The brachial plexus or subclavian artery",B:"The vagus nerve and pulmonary trunk",C:"The optic nerve and hyaloid artery",D:"The inferior vena cava and hepatic sinusoids"},correct:"A",explanation:"An extra cervical rib, especially at C7, may impinge on the brachial plexus or subclavian artery, potentially causing limb anesthesia or vascular symptoms."},
      {id:"emb-011",difficulty:"Easy",topic:"Muscle development",subtopic:"Germ layer origin",question:"Which embryonic origin is correctly matched with its muscle derivative?",options:{A:"Surface ectoderm forms cardiac muscle of the heart tube",B:"Paraxial mesoderm forms most skeletal muscle of the body",C:"Endoderm forms skeletal muscle of the limbs",D:"Neural tube forms smooth muscle of the intestine"},correct:"B",explanation:"Most skeletal muscle is derived from paraxial mesoderm. Smooth muscle is mostly visceral mesoderm-derived, and cardiac muscle comes from visceral mesoderm around the heart tube."},
      {id:"emb-012",difficulty:"Hard",topic:"Muscle development",subtopic:"Dermomyotome and myotome",question:"Cells from the anterolateral lip of the dermomyotome that migrate across the lateral somitic frontier contribute mainly to which muscle groups?",options:{A:"Only intrinsic back muscles and paravertebral muscles",B:"Only extraocular muscles and tongue muscles",C:"Only muscles derived from the second pharyngeal arch",D:"Infrahyoid muscles, abdominal wall muscles, and limb muscles"},correct:"D",explanation:"Cells migrating from the anterolateral lip into the lateral plate mesoderm form abaxial muscles such as infrahyoid, abdominal wall, and limb muscles."},
      {id:"emb-013",difficulty:"Hard",topic:"Muscle development",subtopic:"Primaxial and abaxial domains",question:"Which statement correctly defines the primaxial and abaxial domains?",options:{A:"The primaxial domain contains only paraxial mesoderm cells around the neural tube, while the abaxial domain includes lateral plate mesoderm plus somite cells that crossed the lateral somitic frontier.",B:"The primaxial domain gives rise only to smooth muscle, while the abaxial domain gives rise only to cardiac muscle.",C:"The primaxial domain is derived from endoderm, while the abaxial domain is derived from neural crest cells.",D:"The primaxial domain forms only limb bones, while the abaxial domain forms only vertebral bodies."},correct:"A",explanation:"The primaxial domain is the region around the neural tube containing paraxial mesoderm cells. The abaxial domain includes lateral plate mesoderm and migratory somite cells crossing the lateral somitic frontier."},
      {id:"emb-014",difficulty:"Hard",topic:"Muscle development",subtopic:"Molecular regulation",question:"Which molecular pathway is correctly associated with skeletal muscle differentiation in the dermomyotome?",options:{A:"TBX4 and TBX5 directly induce hyaloid artery regression in developing skeletal muscle.",B:"VEGF inhibits angioblast joining and blocks myotome formation.",C:"BMP4, FGFs, WNT proteins, and SHH signaling contribute to expression of myogenic regulatory factors such as MyoD and MYF5.",D:"Retinoic acid suppresses SHH and prevents all myoblast fusion."},correct:"C",explanation:"BMP4, FGFs, WNT proteins, and SHH signaling help induce myogenic regulatory factors, especially MyoD and MYF5, which activate skeletal muscle development."},
      {id:"emb-015",difficulty:"Medium",topic:"Muscle development",subtopic:"Cardiac and smooth muscle",question:"Which statement correctly describes cardiac muscle development?",options:{A:"Cardiac myoblasts fuse into long multinucleated fibers in the same way as skeletal muscle.",B:"Cardiac muscle develops from visceral mesoderm around the heart tube; myoblasts adhere through intercalated discs but do not fuse.",C:"Cardiac muscle develops from surface ectoderm and forms only after birth.",D:"Cardiac muscle forms from sclerotome cells adjacent to the myotome."},correct:"B",explanation:"Cardiac muscle comes from visceral mesoderm surrounding the heart tube. Cardiac myoblasts develop myofibrils and connect by intercalated discs but do not fuse."},
      {id:"emb-016",difficulty:"Easy",topic:"Limb development",subtopic:"Limb bud and limb segments",question:"Which list correctly matches the three main proximodistal limb segments with their skeletal components?",options:{A:"Stylopod forms carpals and tarsals; Zeugopod forms digits; Autopod forms humerus and femur",B:"Stylopod forms radius and ulna; Zeugopod forms metacarpals; Autopod forms femur only",C:"Stylopod forms hand and foot plates; Zeugopod forms shoulder girdle; Autopod forms ribs",D:"Stylopod forms humerus and femur; Zeugopod forms radius/ulna and tibia/fibula; Autopod forms carpals, metacarpals, digits, tarsals, and metatarsals"},correct:"D",explanation:"The stylopod forms the humerus and femur, the zeugopod forms paired long bones of forearm and leg, and the autopod forms wrist/ankle elements and digits."},
      {id:"emb-017",difficulty:"Medium",topic:"Limb development",subtopic:"Apical ectodermal ridge",question:"What is the primary role of the apical ectodermal ridge during early limb outgrowth?",options:{A:"It directly differentiates into all muscles of the limb.",B:"It forms the superior and inferior vesical arteries.",C:"It maintains the underlying progress zone as rapidly proliferating undifferentiated mesenchyme.",D:"It induces the formation of the septum primum in the common atrium."},correct:"C",explanation:"The AER maintains the progress zone, a region of rapidly proliferating undifferentiated mesenchyme required for proximodistal limb growth."},
      {id:"emb-018",difficulty:"Medium",topic:"Limb development",subtopic:"Limb rotation",question:"Which description correctly explains the final orientation after limb rotation during the 7th week?",options:{A:"The upper limbs rotate laterally so the thumbs lie laterally, while the lower limbs rotate medially so the big toes lie medially.",B:"The upper limbs rotate medially so the thumbs lie medially, while the lower limbs rotate laterally so the big toes lie laterally.",C:"Both upper and lower limbs rotate laterally, placing all extensor compartments anteriorly.",D:"Neither upper nor lower limbs rotate; final orientation is due only to differential growth of digits."},correct:"A",explanation:"The upper limbs rotate 90 degrees laterally, positioning extensors laterally/posteriorly and thumbs laterally. The lower limbs rotate 90 degrees medially, positioning extensors anteriorly and big toes medially."},
      {id:"emb-019",difficulty:"Hard",topic:"Limb development",subtopic:"Joint formation",question:"During synovial joint development, what forms in the region between two chondrifying bone primordia?",options:{A:"A neural crest-derived cartilage plate that becomes the optic cup",B:"A persistent notochordal canal that becomes the nucleus pulposus",C:"A cardiac jelly layer that becomes the atrioventricular canal",D:"A joint interzone whose mesenchyme contributes to articular cartilage, synovial membrane, menisci, and ligaments"},correct:"D",explanation:"Where chondrogenesis is arrested between bone primordia, a joint interzone forms. Its mesenchyme contributes to internal joint structures, while surrounding mesenchyme forms the capsule."},
      {id:"emb-020",difficulty:"Hard",topic:"Limb development",subtopic:"Molecular regulation",question:"Which pairing correctly matches limb outgrowth factors with forelimb and hindlimb identity?",options:{A:"Forelimb: TBX4 and FGF10; Hindlimb: TBX5 and FGF10",B:"Forelimb: TBX5 and FGF10; Hindlimb: TBX4 and FGF10",C:"Forelimb: SHH only; Hindlimb: VEGF only",D:"Forelimb: EN1 and WNT7a; Hindlimb: MyoD and MYF5"},correct:"B",explanation:"Forelimb outgrowth is initiated by TBX5 and FGF10, while hindlimb outgrowth is initiated by TBX4 and FGF10 from lateral plate mesoderm."},
      {id:"emb-021",difficulty:"Hard",topic:"Limb development",subtopic:"Axis patterning",question:"Which statement best describes anteroposterior patterning of the limb bud?",options:{A:"The zone of polarizing activity produces signals involving retinoic acid and SHH, which regulate the anteroposterior axis.",B:"The anterior ectoderm alone produces VEGF, which directly establishes all digit identities.",C:"The septum transversum produces MyoD, which determines thumb-to-little-finger polarity.",D:"The dorsal neural tube produces pulmonary surfactant, which induces the posterior limb border."},correct:"A",explanation:"The ZPA regulates anteroposterior limb patterning. Retinoic acid initiates SHH expression, and SHH is central for anterior-posterior patterning."},
      {id:"emb-022",difficulty:"Medium",topic:"Limb defects",subtopic:"Terminology",question:"Which congenital limb defect is defined as complete absence of one or more extremities?",options:{A:"Meromelia",B:"Micromelia",C:"Amelia",D:"Brachydactyly"},correct:"C",explanation:"Amelia means complete absence of one or more limbs. Meromelia is partial absence, micromelia is abnormal shortening, and brachydactyly refers to shortened digits."},
      {id:"emb-023",difficulty:"Easy",topic:"Cardiovascular development",subtopic:"Vascular development",question:"Which statement correctly distinguishes vasculogenesis from angiogenesis?",options:{A:"Vasculogenesis is sprouting from existing vessels, while angiogenesis is formation from angioblasts.",B:"Vasculogenesis forms vessels by joining angioblasts, while angiogenesis forms vessels by sprouting from pre-existing vessels.",C:"Both terms describe only the formation of lymphatic vessels from neural crest cells.",D:"Vasculogenesis occurs only after birth, while angiogenesis occurs only before gastrulation."},correct:"B",explanation:"Vasculogenesis forms new vessels from angioblasts or blood islands. Angiogenesis forms new vessels by sprouting from existing vessels."},
      {id:"emb-024",difficulty:"Medium",topic:"Aortic arch development",subtopic:"Arch derivatives",question:"Which derivative is correctly matched with the first aortic arch?",options:{A:"Common carotid artery and first part of internal carotid artery",B:"Right pulmonary artery and ductus arteriosus",C:"Proximal right subclavian artery",D:"Maxillary artery"},correct:"D",explanation:"Most of the first aortic arch disappears, but a small remnant persists as the maxillary artery."},
      {id:"emb-025",difficulty:"Medium",topic:"Aortic arch development",subtopic:"Arch derivatives",question:"Which aortic arch forms the common carotid arteries and the first part of the internal carotid arteries?",options:{A:"Third aortic arch",B:"Second aortic arch",C:"Fourth aortic arch",D:"Sixth aortic arch"},correct:"A",explanation:"The third aortic arch forms the common carotid arteries and the proximal part of the internal carotid arteries."},
      {id:"emb-026",difficulty:"Hard",topic:"Aortic arch development",subtopic:"Fourth and sixth arches",question:"Which option correctly describes derivatives of the fourth and sixth aortic arches?",options:{A:"The right fourth arch forms the ductus arteriosus, and the left sixth arch forms the maxillary artery.",B:"The left fourth arch forms the stapedial artery, and the right sixth arch forms the celiac artery.",C:"The fourth arches form only pulmonary arteries, while the sixth arches form only carotid arteries.",D:"The left fourth arch contributes to the aortic arch, the right fourth arch contributes to the proximal right subclavian artery, and the left sixth arch contributes to the ductus arteriosus."},correct:"D",explanation:"The left fourth arch forms part of the aortic arch, the right fourth arch contributes to the proximal right subclavian artery, and the left sixth arch persists partly as the ductus arteriosus."},
      {id:"emb-027",difficulty:"Medium",topic:"Arterial development",subtopic:"Vitelline and umbilical arteries",question:"Which adult arteries are represented by vitelline artery derivatives?",options:{A:"Internal iliac and superior vesical arteries",B:"Celiac and superior mesenteric arteries",C:"Pulmonary arteries and ductus arteriosus",D:"Common carotid and maxillary arteries"},correct:"B",explanation:"Vitelline arteries initially supply the yolk sac and later contribute to arteries of the gut, especially the celiac and superior mesenteric arteries."},
      {id:"emb-028",difficulty:"Medium",topic:"Venous system development",subtopic:"Umbilical veins",question:"Which statement correctly describes development of the ductus venosus?",options:{A:"It forms from the right umbilical vein and becomes the medial umbilical ligament after birth.",B:"It forms from the left vitelline vein and becomes the coronary sinus after birth.",C:"It forms as a direct communication between the left umbilical vein and the right hepatocardiac channel to bypass hepatic sinusoids.",D:"It develops from the anterior cardinal veins and drains the head and neck."},correct:"C",explanation:"The ductus venosus connects the left umbilical vein to the right hepatocardiac channel, allowing oxygenated placental blood to bypass much of the liver sinusoidal plexus."},
      {id:"emb-029",difficulty:"Hard",topic:"Venous system development",subtopic:"Cardinal veins",question:"Which adult vessel forms from the anastomosis between the anterior cardinal veins?",options:{A:"Azygos vein",B:"Left brachiocephalic vein",C:"Superior mesenteric vein",D:"Ligamentum venosum"},correct:"B",explanation:"The anastomosis between the anterior cardinal veins forms the left brachiocephalic vein."},
      {id:"emb-030",difficulty:"Hard",topic:"Venous system development",subtopic:"Inferior vena cava",question:"Which list correctly includes major segmental contributors to the inferior vena cava?",options:{A:"Hepatic, renal, and sacrocardinal segments",B:"Maxillary, hyoid, and stapedial segments",C:"Pulmonary, ductal, and truncal segments",D:"Optic, choroid, and scleral segments"},correct:"A",explanation:"The completed IVC includes hepatic, renal, and sacrocardinal segments, with contributions from vitelline/subcardinal/sacrocardinal systems."},
      {id:"emb-031",difficulty:"Medium",topic:"Heart development",subtopic:"Primary and secondary heart fields",question:"Which description correctly distinguishes the primary heart field from the secondary heart field?",options:{A:"The primary heart field forms only the outflow tract, while the secondary heart field forms only the left atrium.",B:"The primary heart field arises from neural crest, while the secondary heart field arises from endoderm.",C:"The primary heart field contributes to atria, left ventricle, and much of right ventricle; the secondary heart field contributes to part of right ventricle and outflow tract.",D:"Both fields form only vascular endothelium and do not contribute to myocardium."},correct:"C",explanation:"The primary heart field forms the atria, left ventricle, and most of the right ventricle. The secondary heart field contributes to the remaining right ventricle and outflow tract."},
      {id:"emb-032",difficulty:"Easy",topic:"Heart development",subtopic:"Heart tube layers",question:"Which three layers make up the basic heart tube?",options:{A:"Endoderm, neural crest, and dermatome",B:"Sclerotome, myotome, and dermatome",C:"Choroid, sclera, and cornea",D:"Endocardium, myocardium, and epicardium"},correct:"D",explanation:"The heart tube consists of endocardium internally, myocardium as the muscular wall, and epicardium covering the outside."},
      {id:"emb-033",difficulty:"Medium",topic:"Heart development",subtopic:"Cardiac looping",question:"Which statement correctly describes the direction of normal cardiac looping?",options:{A:"The cranial portion bends ventrally, caudally, and to the right, while the caudal portion shifts posterocranially and to the left.",B:"The cranial portion bends dorsally and to the left, while the caudal portion shifts ventrally and to the right.",C:"Both cranial and caudal portions remain fixed while septa form inside the tube.",D:"The tube folds only laterally, with no right-left asymmetry."},correct:"A",explanation:"During normal looping, the cranial portion bends ventrally, caudally, and rightward, while the caudal portion shifts posterocranially and leftward."},
      {id:"emb-034",difficulty:"Hard",topic:"Heart development",subtopic:"Bulbus cordis and truncus arteriosus",question:"Which structure forms the trabeculated part of the primitive right ventricle?",options:{A:"Primitive atrium",B:"Proximal third of the bulbus cordis",C:"Distal truncus arteriosus only",D:"Septum primum"},correct:"B",explanation:"The proximal third of the bulbus cordis becomes trabeculated and forms the primitive right ventricle."},
      {id:"emb-035",difficulty:"Hard",topic:"Sinus venosus development",subtopic:"Right atrium",question:"The smooth-walled part of the right atrium develops mainly from which embryonic structure?",options:{A:"Left vitelline vein",B:"Septum primum",C:"Truncus arteriosus",D:"Right sinus horn of the sinus venosus"},correct:"D",explanation:"The right sinus horn enlarges and is incorporated into the right atrium, forming its smooth-walled part, also called the sinus venarum."},
      {id:"emb-036",difficulty:"Medium",topic:"Cardiac septation",subtopic:"Endocardial cushions",question:"Endocardial cushions are important because they contribute to which cardiac structures?",options:{A:"Only the cranial neuropore and neural tube",B:"Only the aortic arch arteries and vitelline veins",C:"Atrial and ventricular septa, atrioventricular canals and valves, and aortic/pulmonary channels",D:"Only the optic cup and lens vesicle"},correct:"C",explanation:"Endocardial cushions develop in AV and conotruncal regions and help form septa, AV canals, AV valves, and separation of aortic and pulmonary outflow channels."},
      {id:"emb-037",difficulty:"Hard",topic:"Cardiac septation",subtopic:"Atrial septation",question:"During atrial septation, why does the ostium secundum form before the ostium primum is fully closed?",options:{A:"To permanently separate the ventricles before birth",B:"To maintain right-to-left blood flow between primitive atria while the septum primum continues developing",C:"To form the semilunar valves in the truncus arteriosus",D:"To allow the pulmonary veins to drain into the right atrium"},correct:"B",explanation:"Before ostium primum fully closes, apoptosis in the upper septum primum creates the ostium secundum, maintaining fetal right-to-left atrial blood flow."},
      {id:"emb-038",difficulty:"Medium",topic:"Cardiac septation",subtopic:"Outflow tract septation",question:"The aorticopulmonary septum forms through which process?",options:{A:"Direct splitting of the sinus venosus into two venous valves",B:"Fusion of the septum primum with the septum secundum",C:"Degeneration of the muscular interventricular septum",D:"Growth, spiraling, and fusion of opposing truncus swellings to divide the truncus into aortic and pulmonary channels"},correct:"D",explanation:"Opposing truncus swellings grow in a spiral pattern, fuse, and create the aorticopulmonary septum, separating the truncus into aortic and pulmonary outflow tracts."},
      {id:"emb-039",difficulty:"Hard",topic:"Cardiac septation",subtopic:"Ventricular septum",question:"The membranous part of the interventricular septum forms mainly when tissue from which structure closes the interventricular foramen?",options:{A:"Anterior/inferior endocardial cushion and conus septal tissue",B:"Lens vesicle and optic stalk",C:"Cranial neuropore and floor plate",D:"Right umbilical vein and ductus venosus"},correct:"A",explanation:"The muscular interventricular septum leaves an interventricular foramen. Closure involves tissue from the endocardial cushion and conus septum, forming the membranous IV septum."},
      {id:"emb-040",difficulty:"Medium",topic:"Cardiac conduction system",subtopic:"SA and AV nodes",question:"Which statement correctly describes early development of the cardiac conduction system?",options:{A:"Only neural crest cells have pacemaker activity from the beginning.",B:"The SA node forms from the left atrium after pulmonary vein incorporation.",C:"Initially all myocardial cells have pacemaker activity, but pacemaker function later localizes near the superior vena cava as the SA node forms.",D:"The AV node develops from the hyaloid artery inside the optic stalk."},correct:"C",explanation:"Early myocardial cells can beat spontaneously. Pacemaker activity later becomes localized to sinus venosus tissue incorporated near the opening of the superior vena cava, forming the SA node."},
      {id:"emb-041",difficulty:"Easy",topic:"Congenital heart defects",subtopic:"Ventricular septal defect",question:"Which statement is most accurate regarding ventricular septal defects?",options:{A:"They are extremely rare and always involve only the muscular portion of the septum.",B:"They result from failure of the tracheoesophageal septum and primarily affect swallowing.",C:"They are caused by abnormal optic fissure closure and produce retinal coloboma.",D:"They are among the most common congenital heart defects and often involve the membranous part of the interventricular septum."},correct:"D",explanation:"VSDs are very common congenital heart defects. Many involve the membranous part of the interventricular septum."},
      {id:"emb-042",difficulty:"Medium",topic:"Congenital heart defects",subtopic:"Tetralogy of Fallot",question:"Which combination defines Tetralogy of Fallot?",options:{A:"Atrial septal defect, mitral atresia, left ventricular hypertrophy, and patent ductus venosus",B:"Pulmonary stenosis, ventricular septal defect, right ventricular hypertrophy, and overriding aorta",C:"Aortic stenosis, patent foramen ovale, left ventricular hypertrophy, and transposition of abdominal viscera",D:"Tricuspid stenosis, atrial septal defect, left atrial hypertrophy, and ductus arteriosus persistence"},correct:"B",explanation:"Tetralogy of Fallot consists of pulmonary stenosis, VSD, right ventricular hypertrophy, and overriding/dextroposed aorta."},
      {id:"emb-043",difficulty:"Easy",topic:"Respiratory system development",subtopic:"Lung bud",question:"The lung bud first appears as an outgrowth from which embryonic structure?",options:{A:"Dorsal wall of the midgut",B:"Cloacal membrane",C:"Ventral wall of the foregut",D:"Surface ectoderm overlying the optic vesicle"},correct:"C",explanation:"The lung bud appears in the fourth week as an outgrowth from the ventral wall of the foregut."},
      {id:"emb-044",difficulty:"Medium",topic:"Respiratory system development",subtopic:"Tissue origins",question:"Which option correctly matches respiratory components with their embryonic origin?",options:{A:"Respiratory epithelium derives from endoderm, while cartilage, muscle, and connective tissue derive from surrounding visceral mesoderm.",B:"Respiratory epithelium derives from neural crest, while cartilage and muscle derive from surface ectoderm.",C:"Respiratory epithelium derives from paraxial mesoderm, while connective tissue derives from the neural tube.",D:"All respiratory structures derive entirely from lateral plate mesoderm."},correct:"A",explanation:"The epithelial lining of the larynx, trachea, bronchi, and lungs is endodermal, while cartilage, muscle, and connective tissue come from visceral mesoderm."},
      {id:"emb-045",difficulty:"Medium",topic:"Respiratory system development",subtopic:"Tracheoesophageal septum",question:"The tracheoesophageal septum forms by fusion of longitudinal ridges and separates the foregut into which structures?",options:{A:"Right and left atria",B:"Dorsal pancreas and ventral pancreas",C:"Foregut and hindgut",D:"Anterior lung bud/respiratory primordium and posterior esophagus"},correct:"D",explanation:"The tracheoesophageal ridges fuse to form the tracheoesophageal septum, separating the respiratory primordium anteriorly from the esophagus posteriorly."},
      {id:"emb-046",difficulty:"Medium",topic:"Respiratory system development",subtopic:"Bronchial branching",question:"Which statement correctly describes bronchial bud development?",options:{A:"The right main bronchus forms two secondary bronchi, and the left forms three.",B:"The right main bronchus forms three secondary bronchi, and the left forms two.",C:"Both lungs form exactly ten secondary bronchi.",D:"The bronchial buds do not branch until after birth."},correct:"B",explanation:"In the fifth week, the bronchial buds enlarge into right and left main bronchi. The right forms three secondary bronchi, and the left forms two."},
      {id:"emb-047",difficulty:"Easy",topic:"Digestive system development",subtopic:"Primitive gut tube",question:"The primitive gut tube forms mainly because of which embryonic process?",options:{A:"Fusion of the optic vesicles with surface ectoderm",B:"Regression of all vitelline arteries",C:"Cephalocaudal and lateral folding incorporate part of the endoderm-lined yolk sac cavity into the embryo.",D:"Migration of neural crest cells into the dorsal mesocardium"},correct:"C",explanation:"Cephalocaudal and lateral folding incorporate part of the yolk sac cavity into the embryo, creating the endoderm-lined primitive gut tube."},
      {id:"emb-048",difficulty:"Medium",topic:"Foregut development",subtopic:"Stomach rotation",question:"Which statement correctly describes stomach rotation and its consequence for vagal innervation?",options:{A:"The stomach rotates 90 degrees around its longitudinal axis, so its left side faces anteriorly and the left vagus becomes anterior.",B:"The stomach rotates 270 degrees counterclockwise around the superior mesenteric artery, moving the cecum into the right iliac fossa.",C:"The stomach does not rotate; the greater curvature forms by equal growth of both walls.",D:"The stomach rotates medially with the lower limb, causing the pylorus to remain in the midline."},correct:"A",explanation:"The stomach rotates 90 degrees around its longitudinal axis. The original left side becomes anterior, so the left vagus supplies the anterior stomach."},
      {id:"emb-049",difficulty:"Medium",topic:"Foregut development",subtopic:"Liver, gallbladder, and pancreas",question:"Which statement correctly describes pancreatic development?",options:{A:"The pancreas develops only from one dorsal bud, while the ventral bud forms the spleen.",B:"The pancreas develops from dorsal and ventral endodermal buds; the ventral bud forms the uncinate process and inferior head.",C:"The pancreas develops from ectodermal placodes and forms before the liver bud.",D:"The pancreatic ducts develop entirely from vitelline veins."},correct:"B",explanation:"The pancreas forms from dorsal and ventral buds from duodenal endoderm. The ventral bud forms the uncinate process and inferior part of the pancreatic head."},
      {id:"emb-050",difficulty:"Medium",topic:"Foregut defects",subtopic:"Clinical terminology",question:"Annular pancreas is clinically important mainly because it can cause which problem?",options:{A:"Failure of the cranial neuropore to close",B:"Compression of the brachial plexus by a cervical rib",C:"Fusion of fingers or toes",D:"Constriction or obstruction of the duodenum"},correct:"D",explanation:"Annular pancreas can encircle and constrict the duodenum, potentially causing complete duodenal obstruction."},
      {id:"emb-051",difficulty:"Easy",topic:"Midgut development",subtopic:"Derivatives",question:"Which list contains midgut derivatives?",options:{A:"Distal duodenum, jejunum, ileum, cecum, appendix, ascending colon, and proximal two-thirds of transverse colon",B:"Esophagus, stomach, liver, gallbladder, pancreas, and lower respiratory tract",C:"Distal one-third of transverse colon, descending colon, sigmoid colon, rectum, and superior anal canal",D:"Kidney, ureter, bladder trigone, gonads, and adrenal cortex"},correct:"A",explanation:"The midgut forms the distal duodenum, jejunum, ileum, cecum, appendix, ascending colon, and proximal two-thirds of the transverse colon."},
      {id:"emb-052",difficulty:"Hard",topic:"Midgut development",subtopic:"Physiological herniation and rotation",question:"Which statement correctly describes normal midgut rotation?",options:{A:"The midgut rotates 90 degrees clockwise entirely after birth.",B:"The midgut rotates 180 degrees clockwise around the celiac trunk.",C:"The primary intestinal loop rotates 270 degrees counterclockwise around the superior mesenteric artery, with the first 90 degrees during herniation and the remaining 180 degrees during return.",D:"The midgut does not rotate; it only lengthens and remains attached to the yolk sac."},correct:"C",explanation:"Normal midgut rotation totals 270 degrees counterclockwise around the superior mesenteric artery. The first 90 degrees occurs during herniation, and the remaining 180 degrees occurs during return to the abdomen."},
      {id:"emb-053",difficulty:"Medium",topic:"Hindgut development",subtopic:"Cloaca and anal canal",question:"Which statement correctly describes development of the cloaca and anal canal?",options:{A:"The cloaca remains undivided and forms only the rectum.",B:"The lower two-thirds of the anal canal comes from hindgut endoderm, while the upper one-third comes from ectoderm.",C:"The urorectal septum divides the cloaca into a posterior urogenital sinus and anterior anal canal.",D:"The cloaca is divided by the urorectal septum into anterior urogenital sinus and posterior anal canal; the upper anal canal is endodermal and the lower part is ectodermal."},correct:"D",explanation:"The urorectal septum divides the cloaca into anterior urogenital sinus and posterior anal canal. The upper anal canal is hindgut endoderm-derived, and the lower part comes from ectoderm around the proctodeum."},
      {id:"emb-054",difficulty:"Medium",topic:"Hindgut defects",subtopic:"Congenital megacolon",question:"Congenital megacolon is associated with which developmental abnormality?",options:{A:"Failure of the septum primum to form the ostium secundum",B:"Absence of parasympathetic ganglia in the bowel wall",C:"Persistence of the right umbilical vein",D:"Failure of the optic vesicle to contact surface ectoderm"},correct:"B",explanation:"Congenital megacolon results from absence of parasympathetic ganglia in the bowel wall, causing impaired motility and bowel dilation."},
      {id:"emb-055",difficulty:"Easy",topic:"Central nervous system development",subtopic:"Neural tube and brain vesicles",question:"Which statement correctly describes early CNS development?",options:{A:"The CNS originates from endoderm and begins as the primitive gut tube.",B:"The cranial neuropore closes after the caudal neuropore, usually around day 35.",C:"The CNS originates from ectoderm as the neural plate; neural folds fuse to form the neural tube, with cranial closure around day 25 and caudal closure around day 28.",D:"The CNS develops from lateral plate mesoderm and forms only after limb buds appear."},correct:"C",explanation:"The CNS originates from ectoderm as the neural plate. Neural tube closure occurs first cranially around day 25 and then caudally around day 28."},
      {id:"emb-056",difficulty:"Medium",topic:"Central nervous system development",subtopic:"Neural tube plates",question:"Which neural tube regions are correctly matched with their main functional association?",options:{A:"Basal plate contains motor neurons; alar plate contains sensory neurons; floor and roof plates are connecting regions",B:"Basal plate contains sensory neurons; alar plate contains motor neurons; roof plate forms skeletal muscle",C:"Floor plate forms lens vesicle; roof plate forms cardiac jelly",D:"Alar plate forms vertebral body; basal plate forms intervertebral disc"},correct:"A",explanation:"The basal plate contains motor neurons, the alar plate contains sensory neurons, and the roof and floor plates connect the two sides of the developing neural tube."},
      {id:"emb-057",difficulty:"Hard",topic:"Central nervous system development",subtopic:"Brain vesicles",question:"Which option correctly matches secondary brain vesicles with their derivatives?",options:{A:"Telencephalon forms medulla oblongata; myelencephalon forms cerebral hemispheres",B:"Mesencephalon forms thalamus and hypothalamus; diencephalon forms colliculi only",C:"Metencephalon forms spinal cord; prosencephalon forms only the pons",D:"Myelencephalon forms medulla oblongata; metencephalon forms cerebellum; diencephalon forms thalamus and hypothalamus; telencephalon forms cerebral hemispheres"},correct:"D",explanation:"The myelencephalon forms the medulla, the metencephalon contributes to the cerebellum, the diencephalon forms thalamic/hypothalamic regions, and the telencephalon forms cerebral hemispheres."},
      {id:"emb-058",difficulty:"Medium",topic:"Eye development",subtopic:"Optic vesicle, optic cup, and lens",question:"Which sequence correctly describes early development of the eye?",options:{A:"Lens vesicle forms first, then induces the foregut to create optic vesicles.",B:"Optic grooves form in the forebrain, become optic vesicles after neural tube closure, contact surface ectoderm, and induce lens formation while invaginating into the optic cup.",C:"The optic cup develops from mesoderm and later becomes the corneal epithelium only.",D:"The choroid fissure forms from the cloacal membrane and gives rise to the stomach."},correct:"B",explanation:"Eye development begins with optic grooves in the forebrain. These become optic vesicles, contact surface ectoderm to induce lens formation, and invaginate to form the double-walled optic cup."},
      {id:"emb-059",difficulty:"Hard",topic:"Eye development",subtopic:"Retina, iris, and ciliary body",question:"Which statement correctly describes derivatives of the optic cup layers?",options:{A:"The outer layer forms the neural retina, while the inner layer forms only the corneal epithelium.",B:"The outer layer forms the lens, while the inner layer forms the sclera.",C:"The outer layer forms pigmented retina; the posterior part of the inner layer forms neural retina, while the anterior part contributes to pars iridica and pars ciliaris retinae.",D:"Both layers disappear completely and are replaced by mesenchyme."},correct:"C",explanation:"The outer optic cup layer forms the pigmented retina. The posterior inner layer forms the neural retina, and the anterior inner layer contributes to the iris and ciliary body retina."},
      {id:"emb-060",difficulty:"Hard",topic:"Eye development",subtopic:"Cornea, vitreous body, and optic nerve",question:"Which statement correctly combines several technical features of eye development?",options:{A:"The corneal epithelium derives from surface ectoderm, mesenchyme contributes to corneal stroma and inner lining, hyaloid vessels enter through the choroid fissure, and retinal axons in the optic stalk form the optic nerve.",B:"The cornea derives entirely from endoderm, the vitreous body forms from the notochord, and the optic nerve forms from the first aortic arch.",C:"The hyaloid artery persists as the adult central canal of the spinal cord, while the optic stalk becomes the ductus venosus.",D:"The anterior chamber forms by fusion of the septum primum and septum secundum, and the optic nerve develops from the sclerotome."},correct:"A",explanation:"The corneal epithelium is surface ectoderm-derived, while mesenchyme contributes to deeper corneal structures. Hyaloid vessels enter through the choroid fissure, and retinal axons grow through the optic stalk to form the optic nerve."},
    ]},
    {name:"Lymphatic System",questions:[
      {id:"lym-001",difficulty:"Medium",topic:"Lymphoid organs",subtopic:"Primary and secondary lymphoid organs",question:"Which statement correctly distinguishes primary from secondary lymphoid organs?",options:{A:"Primary lymphoid organs are sites where lymphocytes originate, while secondary lymphoid organs are sites where immune responses and lymphocyte maturation/activation occur.",B:"Primary lymphoid organs include tonsils and Peyer's patches, while secondary lymphoid organs include bone marrow only.",C:"Primary lymphoid organs only filter lymph, while secondary lymphoid organs produce erythrocytes.",D:"Primary and secondary lymphoid organs are identical terms for the same structures."},correct:"A",explanation:"Primary lymphoid organs include thymus and bone marrow, where lymphocytes originate or differentiate. Secondary lymphoid organs include lymph nodes, tonsils, Peyer's patches and spleen, where immune responses occur."},
      {id:"lym-002",difficulty:"Hard",topic:"Thymus",subtopic:"Embryological origin",question:"The thymus is derived embryologically from which structure according to the notes?",options:{A:"First pharyngeal arch",B:"Third pharyngeal arch",C:"Second pharyngeal pouch only",D:"Neural crest-derived paraxial mesoderm"},correct:"B",explanation:"The notes describe the thymus as a primary lymphoid organ derived from the third pharyngeal arch."},
      {id:"lym-003",difficulty:"Medium",topic:"Thymus",subtopic:"Position and syntopy",question:"Where is the thymus primarily located?",options:{A:"Posterior abdominal wall, anterior to the kidneys",B:"Right upper quadrant of the abdomen, beneath the liver",C:"Superior mediastinum, posterior to the manubrium of the sternum",D:"Within the inguinal canal, deep to the superficial inguinal lymph nodes"},correct:"C",explanation:"The thymus is an asymmetrical flat organ located mainly in the superior mediastinum behind the manubrium, with possible extension into the neck and anterior mediastinum."},
      {id:"lym-004",difficulty:"Hard",topic:"Thymus",subtopic:"Histological organization",question:"Which feature is characteristic of the thymic medulla?",options:{A:"Dense B-lymphocyte nodules with germinal centers",B:"Venous sinusoids lined by stave cells",C:"Lacteals filled with absorbed fats",D:"Fewer lymphocytes, more reticular epithelial cells, and Hassall's corpuscles"},correct:"D",explanation:"The thymic medulla contains fewer lymphocytes than the cortex, more reticular epithelial cells, and Hassall's corpuscles made of concentrically arranged epithelial reticular cells filled with keratin."},
      {id:"lym-005",difficulty:"Hard",topic:"Thymus",subtopic:"Function",question:"Which function best describes the thymus?",options:{A:"T-lymphocyte differentiation and removal of T cells reactive against self-antigens",B:"Filtration of old erythrocytes from blood through open splenic circulation",C:"Absorption of digested fats from the intestinal lumen into lacteals",D:"Drainage of the right upper limb directly into the cisterna chyli"},correct:"A",explanation:"The thymus is the site of T-lymphocyte differentiation and thymic selection, where self-reactive T lymphocytes are removed."},
      {id:"lym-006",difficulty:"Medium",topic:"Thymus",subtopic:"Age-related changes",question:"What happens to the thymus after puberty?",options:{A:"It becomes the main site of erythrocyte destruction.",B:"It atrophies and is progressively replaced by adipose tissue.",C:"It transforms into the spleen.",D:"It begins producing bile and pancreatic enzymes."},correct:"B",explanation:"The thymus is highly active at birth and during early childhood, but after puberty its activity decreases and it undergoes fatty replacement."},
      {id:"lym-007",difficulty:"Hard",topic:"Thymus",subtopic:"Vasculature",question:"Which set of arteries contributes to the arterial supply of the thymus according to the PDF?",options:{A:"Splenic artery and short gastric arteries",B:"Superior mesenteric artery and inferior mesenteric artery",C:"Anterior intercostal arteries, superior/inferior thyroid branches, and internal thoracic artery branches",D:"Testicular arteries and lumbar arteries only"},correct:"C",explanation:"The thymus receives arterial supply from anterior intercostal arteries and small branches from the superior thyroid, inferior thyroid and internal thoracic arteries."},
      {id:"lym-008",difficulty:"Medium",topic:"Lymph node",subtopic:"General function",question:"What is the main function of lymph nodes?",options:{A:"To produce bile and store glycogen",B:"To destroy old erythrocytes through splenic cords",C:"To oxygenate lymph before it enters the bloodstream",D:"To filter lymph and support immune responses against detected antigens"},correct:"D",explanation:"Lymph nodes filter lymph before it re-enters the bloodstream and contain immune cells such as T cells, B cells, macrophages and APCs."},
      {id:"lym-009",difficulty:"Hard",topic:"Lymph node",subtopic:"Cortex",question:"Which lymph node region contains lymphoid nodules formed mainly by B-lymphocytes?",options:{A:"Cortex",B:"Paracortex",C:"Medullary sinus only",D:"Hilum only"},correct:"A",explanation:"The cortex lies beneath the capsule and contains lymphoid nodules composed mainly of B-lymphocytes."},
      {id:"lym-010",difficulty:"Hard",topic:"Lymph node",subtopic:"Paracortex",question:"The paracortex of a lymph node is mainly characterized by which feature?",options:{A:"It is the main site of old red blood cell destruction.",B:"It contains T-lymphocytes and high endothelial venules.",C:"It contains Hassall's corpuscles arranged concentrically.",D:"It is the primary site of fat absorption from the gut lumen."},correct:"B",explanation:"The paracortex lacks B-cell nodules and is rich in T-lymphocytes. It also contains high endothelial venules that allow rapid lymphocyte entry."},
      {id:"lym-011",difficulty:"Hard",topic:"Lymph node",subtopic:"Medulla",question:"Which statement correctly describes the medulla of a lymph node?",options:{A:"It contains only epithelial reticular cells and no lymphocytes.",B:"It is the first sinus entered directly from afferent lymphatic vessels.",C:"It contains medullary cords rich in B-lymphocytes/macrophages and medullary sinuses containing lymph and macrophages.",D:"It is located outside the capsule and drains into the thoracic duct directly."},correct:"C",explanation:"The medulla contains medullary cords with B-lymphocytes and macrophages, separated by medullary sinuses that contain lymph and macrophages."},
      {id:"lym-012",difficulty:"Hard",topic:"Lymph node",subtopic:"Lymph flow",question:"Which sequence correctly describes lymph flow through a lymph node?",options:{A:"Efferent lymph vessel → medullary sinus → cortical sinus → subcapsular sinus → afferent lymph vessel",B:"Afferent lymph vessel → subcapsular sinus → cortical sinus → medullary sinus → efferent lymph vessel",C:"Afferent lymph vessel → hilum → thoracic duct → subcapsular sinus",D:"Medullary cord → Hassall's corpuscle → paracortex → splenic sinus"},correct:"B",explanation:"Lymph enters via afferent lymphatic vessels, passes through subcapsular, cortical and medullary sinuses, and exits via an efferent lymphatic vessel at the hilum."},
      {id:"lym-013",difficulty:"Medium",topic:"Sentinel lymph node",subtopic:"Clinical relevance",question:"What is a sentinel lymph node?",options:{A:"The largest lymph node in the body",B:"A thymic corpuscle involved in T-cell selection",C:"A splenic lymphoid nodule surrounding a central arteriole",D:"The first lymph node that drains lymph from a particular organ or region"},correct:"D",explanation:"A sentinel lymph node is the first node draining an organ or region, making it clinically important in the spread of malignancy."},
      {id:"lym-014",difficulty:"Hard",topic:"Main lymphatic ducts",subtopic:"Thoracic duct",question:"Which drainage territory belongs to the thoracic duct?",options:{A:"Lower body, left upper limb, and left head and neck",B:"Only the right upper limb and right side of the head",C:"Only the thoracic wall and right lung",D:"Only the thymus and spleen"},correct:"A",explanation:"The thoracic duct drains the whole lower body, left upper limb, and left head and neck into the left venous angle."},
      {id:"lym-015",difficulty:"Medium",topic:"Main lymphatic ducts",subtopic:"Right lymphatic duct",question:"The right lymphatic duct drains mainly into which site?",options:{A:"Cisterna chyli",B:"Portal vein",C:"Right venous angle",D:"Left venous angle"},correct:"C",explanation:"The right lymphatic duct drains lymph from the right upper quadrant of the body into the right venous angle."},
      {id:"lym-016",difficulty:"Hard",topic:"MALT",subtopic:"Mucosa-associated lymphoid tissue",question:"Which statement best describes MALT?",options:{A:"Encapsulated lymphoid tissue found only in the spleen",B:"Non-encapsulated lymphoid tissue in mucosal organs exposed to the external environment",C:"A lymphatic duct that drains into the right venous angle",D:"A type of thymic epithelial corpuscle found in the medulla"},correct:"B",explanation:"MALT is non-encapsulated lymphoid tissue found in mucosal organs of the digestive, respiratory and genitourinary tracts, which are exposed to pathogens from the external environment."},
      {id:"lym-017",difficulty:"Medium",topic:"Spleen",subtopic:"Organ classification",question:"Which statement correctly describes the spleen?",options:{A:"It is a primary lymphoid organ located in the superior mediastinum.",B:"It is a secondary lymphoid organ located in the upper left abdomen.",C:"It is a non-encapsulated MALT structure located in the ileum.",D:"It is a lymphatic duct arising from the cisterna chyli."},correct:"B",explanation:"The spleen is a secondary lymphoid organ located in the upper left quadrant of the abdomen, under the diaphragm and ribcage."},
      {id:"lym-018",difficulty:"Hard",topic:"Spleen",subtopic:"Peritoneal relations",question:"Which ligaments connect the spleen to nearby organs?",options:{A:"Gastrosplenic ligament to the stomach and splenorenal ligament to the kidney",B:"Falciform ligament to the liver and hepatoduodenal ligament to the duodenum",C:"Broad ligament to the uterus and suspensory ligament to the ovary",D:"Median umbilical ligament to the bladder and mesoappendix to the appendix"},correct:"A",explanation:"The spleen is attached to the stomach by the gastrosplenic ligament and to the kidney by the splenorenal ligament."},
      {id:"lym-019",difficulty:"Hard",topic:"Spleen",subtopic:"White and red pulp",question:"Which statement correctly distinguishes white pulp from red pulp?",options:{A:"White pulp contains only erythrocytes, while red pulp contains only lymphocytes.",B:"White pulp is adipose tissue, while red pulp is bone marrow.",C:"White pulp is lymphoid tissue, while red pulp contains blood cells and participates in blood filtration.",D:"White pulp forms Hassall's corpuscles, while red pulp forms thymic cortex."},correct:"C",explanation:"The spleen contains white pulp rich in lymphoid tissue and red pulp filled with blood cells, venous sinusoids and splenic cords."},
      {id:"lym-020",difficulty:"Hard",topic:"Spleen",subtopic:"Red pulp function",question:"In open splenic circulation, why are old erythrocytes removed?",options:{A:"They are actively pumped into the thymus for selection.",B:"They cannot pass efficiently through gaps between stave cells due to reduced flexibility and are phagocytosed by macrophages.",C:"They enter lacteals and are digested by pancreatic enzymes.",D:"They are filtered only by high endothelial venules in the lymph node paracortex."},correct:"B",explanation:"Old erythrocytes lose membrane flexibility and cannot pass between stave cells lining venous sinusoids, so they are engulfed by macrophages in splenic cords."},
      {id:"lym-021",difficulty:"Medium",topic:"Spleen",subtopic:"Blood supply",question:"What is the main arterial supply of the spleen?",options:{A:"Superior mesenteric artery",B:"Inferior mesenteric artery",C:"Splenic artery from the celiac trunk",D:"Internal iliac artery"},correct:"C",explanation:"The spleen is supplied by the splenic artery, a branch of the celiac trunk."},
      {id:"lym-022",difficulty:"Hard",topic:"Spleen",subtopic:"Segmental blood supply",question:"Why can specific sections of the spleen be surgically removed more easily?",options:{A:"Because splenic arterial branches form non-anastomosing vascular segments.",B:"Because the spleen has no capsule.",C:"Because the spleen has only venous drainage and no arterial supply.",D:"Because the spleen is supplied directly by the right lymphatic duct."},correct:"A",explanation:"Splenic arterial branches do not anastomose significantly, creating vascular segments that allow segmental splenectomy."},
      {id:"lym-023",difficulty:"Medium",topic:"Spleen",subtopic:"Venous drainage",question:"The splenic vein combines with which vessel to form the portal vein?",options:{A:"Inferior vena cava",B:"Superior mesenteric vein",C:"Left renal vein",D:"Internal iliac vein"},correct:"B",explanation:"The splenic vein joins the superior mesenteric vein to form the portal vein."},
      {id:"lym-024",difficulty:"Hard",topic:"Spleen",subtopic:"Histological blood flow",question:"Which sequence correctly describes splenic arterial blood flow into the pulp?",options:{A:"Splenic artery → trabecular arteries → central arterioles surrounded by PALS → penicillar arterioles",B:"Splenic artery → lacteals → celiac lymph nodes → cisterna chyli",C:"Splenic artery → subcapsular sinus → cortical sinus → medullary sinus",D:"Splenic artery → high endothelial venules → paracortex → efferent lymphatic"},correct:"A",explanation:"Splenic artery branches enter as trabecular arteries, leave trabeculae as central arterioles surrounded by periarteriolar lymphoid sheath, then give rise to penicillar arterioles."},
      {id:"lym-025",difficulty:"Hard",topic:"Head and neck lymphatics",subtopic:"Superficial and deep vessels",question:"Which statement correctly describes lymphatic vessels of the head and neck?",options:{A:"Deep lymphatics drain directly into the popliteal nodes.",B:"Superficial vessels drain lymph from scalp, face and neck into a superficial ring of nodes at the head-neck junction.",C:"The right jugular trunk always empties directly into the thoracic duct.",D:"The left jugular trunk drains into the right venous angle."},correct:"B",explanation:"Superficial vessels drain the scalp, face and neck into superficial lymph nodes at the junction of the head and neck. Deep vessels converge into jugular lymphatic trunks."},
      {id:"lym-026",difficulty:"Hard",topic:"Head and neck lymph nodes",subtopic:"Occipital and mastoid nodes",question:"Which lymph nodes collect lymph from the occipital area of the scalp?",options:{A:"Submental lymph nodes",B:"Parotid lymph nodes",C:"Occipital lymph nodes",D:"Pretracheal lymph nodes"},correct:"C",explanation:"Occipital lymph nodes are located at the back of the head near the lateral border of trapezius and collect lymph from the occipital scalp."},
      {id:"lym-027",difficulty:"Medium",topic:"Head and neck lymph nodes",subtopic:"Submental nodes",question:"The submental lymph nodes drain which region?",options:{A:"Lower lip, floor of the oral cavity, and apex of the tongue",B:"Posterior scalp and upper ear",C:"External acoustic meatus and nasal cavity only",D:"Deep thoracic wall and diaphragm"},correct:"A",explanation:"Submental lymph nodes lie superficial to the mylohyoid muscle and drain the lower lip, floor of the oral cavity and apex of the tongue."},
      {id:"lym-028",difficulty:"Medium",topic:"Head and neck lymph nodes",subtopic:"Submandibular nodes",question:"Which lymph nodes are located below the mandible in the submandibular triangle and receive lymph from cheeks, lateral nose, upper lip and also from submental/facial nodes?",options:{A:"Occipital nodes",B:"Submandibular nodes",C:"Mastoid nodes",D:"Supraclavicular nodes"},correct:"B",explanation:"Submandibular lymph nodes are located below the mandible and drain the cheeks, lateral nose and upper lip, also receiving lymph from submental and facial nodes."},
      {id:"lym-029",difficulty:"Hard",topic:"Deep cervical lymph nodes",subtopic:"Drainage",question:"Which statement about deep cervical lymph nodes is correct?",options:{A:"They receive all lymph from the head and neck and are arranged vertically near the internal jugular vein.",B:"They are located only in the popliteal fossa.",C:"They drain directly into the intestinal lymphatic trunk.",D:"They are found only inside the thymic medulla."},correct:"A",explanation:"Deep cervical nodes receive all lymph from the head and neck and are organized vertically close to the internal jugular vein; their efferents form the jugular lymphatic trunks."},
      {id:"lym-030",difficulty:"Hard",topic:"Thoracic wall lymphatics",subtopic:"Deep drainage",question:"Which deep lymph node group of the thoracic wall drains into the bronchomediastinal trunk?",options:{A:"Popliteal lymph nodes",B:"Celiac lymph nodes",C:"Parasternal lymph nodes",D:"Lumbar lymph nodes"},correct:"C",explanation:"Parasternal lymph nodes drain into the bronchomediastinal trunk. Phrenic nodes drain into parasternal nodes."},
      {id:"lym-031",difficulty:"Hard",topic:"Breast lymph drainage",subtopic:"Axillary drainage",question:"Approximately 75% of lymph from the breast drains first mainly to which lymph nodes?",options:{A:"Pectoral lymph nodes, then axillary lymph nodes",B:"Popliteal lymph nodes, then inguinal lymph nodes",C:"Celiac lymph nodes, then cisterna chyli",D:"Lumbar lymph nodes, then thoracic duct"},correct:"A",explanation:"About 75% of breast lymph drains into pectoral lymph nodes and then axillary lymph nodes."},
      {id:"lym-032",difficulty:"Hard",topic:"Breast lymph drainage",subtopic:"Parasternal drainage",question:"The remaining 25% of breast lymph mainly drains into which lymph nodes?",options:{A:"Deep cervical lymph nodes",B:"Parasternal lymph nodes",C:"Superior mesenteric lymph nodes",D:"Occipital lymph nodes"},correct:"B",explanation:"The remaining 25% of breast lymph drains into parasternal lymph nodes, which drain into bronchomediastinal trunks."},
      {id:"lym-033",difficulty:"Hard",topic:"Thoracic duct",subtopic:"Course",question:"Which statement correctly describes the thoracic duct course?",options:{A:"It begins in the right venous angle and descends into the pelvis.",B:"It begins at the thymus and terminates in the portal vein.",C:"It begins from the cisterna chyli around L1/L2, enters the thorax through the aortic hiatus, crosses left around T4-T6, and drains into the left venous angle.",D:"It begins in the spleen and drains directly into the superior mesenteric vein."},correct:"C",explanation:"The thoracic duct arises from the cisterna chyli at L1/L2, enters the thorax via the aortic hiatus at T12, ascends, crosses left at T4-T6, and drains into the left venous angle."},
      {id:"lym-034",difficulty:"Hard",topic:"Lung lymph drainage",subtopic:"Superficial and deep plexuses",question:"Which statement correctly describes lung lymphatic drainage?",options:{A:"The superficial plexus is located in the visceral pleura and drains to bronchopulmonary nodes; the deep plexus is in bronchial submucosa and drains toward pulmonary nodes.",B:"Both plexuses drain directly to the inguinal lymph nodes.",C:"The superficial plexus drains only the pancreas and liver.",D:"The deep plexus drains directly into the portal vein."},correct:"A",explanation:"The superficial plexus of the lungs and visceral pleura drains into bronchopulmonary nodes. The deep plexus in bronchial submucosa drains the lung root into pulmonary nodes, then bronchopulmonary and tracheobronchial nodes."},
      {id:"lym-035",difficulty:"Medium",topic:"Abdominal lymph nodes",subtopic:"Pre-aortic nodes",question:"Which lymph node groups are classified as pre-aortic lymph nodes?",options:{A:"Popliteal, superficial inguinal, and deep inguinal nodes",B:"Occipital, mastoid, and preauricular nodes",C:"Anterior, central, and apical axillary nodes",D:"Celiac, superior mesenteric, and inferior mesenteric lymph nodes"},correct:"D",explanation:"Pre-aortic lymph nodes lie in front of the aorta and are grouped into celiac, superior mesenteric and inferior mesenteric lymph nodes."},
      {id:"lym-036",difficulty:"Hard",topic:"Stomach lymph drainage",subtopic:"Celiac pathway",question:"Which pathway correctly describes stomach lymph drainage?",options:{A:"Stomach lymphatics → gastric and gastro-omental lymph nodes → celiac lymph nodes → intestinal lymphatic trunk → cisterna chyli",B:"Stomach lymphatics → popliteal lymph nodes → lumbar trunk → right venous angle",C:"Stomach lymphatics → superficial inguinal nodes → external iliac nodes only",D:"Stomach lymphatics → deep cervical nodes → jugular trunk"},correct:"A",explanation:"Stomach lymph vessels travel along the curvatures to gastric and gastro-omental nodes, then celiac nodes, then the intestinal trunk, and finally the cisterna chyli."},
      {id:"lym-037",difficulty:"Hard",topic:"Liver lymph drainage",subtopic:"Superficial lymphatics",question:"The superficial lymphatics from the anterior aspect of the liver capsule drain first mainly into which nodes?",options:{A:"Popliteal lymph nodes",B:"Hepatic lymph nodes at the porta hepatis",C:"Submental lymph nodes",D:"Axillary apical nodes"},correct:"B",explanation:"Superficial lymphatics from the anterior liver capsule drain to hepatic lymph nodes at the porta hepatis, then to celiac nodes and the cisterna chyli."},
      {id:"lym-038",difficulty:"Hard",topic:"Pancreas lymph drainage",subtopic:"Regional drainage",question:"Which statement about pancreatic lymph drainage is correct?",options:{A:"The head drains mainly to pancreaticoduodenal lymph nodes, while the tail drains toward splenic lymph nodes.",B:"The pancreas drains only to superficial inguinal lymph nodes.",C:"The tail drains directly into the right lymphatic duct without lymph nodes.",D:"The pancreatic body drains into occipital nodes."},correct:"A",explanation:"The pancreatic head drains to pancreaticoduodenal nodes, while the tail drains to splenic nodes along the splenic artery; these pathways ultimately reach celiac nodes and cisterna chyli."},
      {id:"lym-039",difficulty:"Hard",topic:"Small intestine lymph drainage",subtopic:"Lacteals and mesenteric nodes",question:"Which sequence best describes lymph drainage from most of the small intestine?",options:{A:"Lacteals → juxta-intestinal nodes → intermediate mesenteric nodes → superior mesenteric nodes → celiac nodes → cisterna chyli",B:"Lacteals → submental nodes → jugular trunk → right venous angle",C:"Lacteals → popliteal nodes → superficial inguinal nodes → external iliac nodes",D:"Lacteals → pulmonary nodes → tracheobronchial nodes → bronchomediastinal trunk"},correct:"A",explanation:"Small intestinal lacteals drain into mesenteric lymph nodes, including juxta-intestinal and intermediate nodes, then superior mesenteric nodes, celiac nodes and cisterna chyli."},
      {id:"lym-040",difficulty:"Hard",topic:"Large intestine lymph drainage",subtopic:"Colon segments",question:"Which drainage pairing is correct?",options:{A:"Ascending colon → inferior mesenteric lymph nodes",B:"Descending colon → left colic lymph nodes → inferior mesenteric lymph nodes",C:"Appendix → internal iliac lymph nodes only",D:"Transverse colon → lumbar lymph nodes directly"},correct:"B",explanation:"The descending colon drains to left colic lymph nodes, then to inferior mesenteric lymph nodes and onward to cisterna chyli via the intestinal lymphatic trunk."},
      {id:"lym-041",difficulty:"Hard",topic:"Rectum and anal canal",subtopic:"Segmental drainage",question:"Which statement about anal canal lymph drainage is correct?",options:{A:"Above the pectinate line drains to internal iliac nodes; below the pectinate line drains to superficial inguinal nodes.",B:"Above and below the pectinate line both drain only to celiac nodes.",C:"Below the pectinate line drains directly to deep cervical nodes.",D:"The anal canal has no lymphatic drainage."},correct:"A",explanation:"Above the pectinate line, lymph drains to internal iliac nodes. Below the pectinate line, lymph drains to superficial inguinal nodes."},
      {id:"lym-042",difficulty:"Hard",topic:"Male reproductive lymph drainage",subtopic:"Testis and epididymis",question:"Where do the testis and epididymis primarily drain lymph?",options:{A:"Superficial inguinal lymph nodes only",B:"Right or left lumbar lymph nodes, then para-aortic/lumbar trunks toward cisterna chyli",C:"Deep cervical lymph nodes",D:"Pectoral lymph nodes"},correct:"B",explanation:"The right and left testes and epididymides drain to the corresponding lumbar lymph nodes, then to para-aortic nodes/lumbar trunks and cisterna chyli."},
      {id:"lym-043",difficulty:"Hard",topic:"Male reproductive lymph drainage",subtopic:"Scrotum and penis",question:"Which statement about external male genital lymph drainage is correct?",options:{A:"The scrotum drains mainly to superficial inguinal lymph nodes.",B:"The skin of the penis drains only to celiac nodes.",C:"The glans penis drains directly to the thoracic duct without nodes.",D:"The testes and scrotum have identical primary lymph drainage."},correct:"A",explanation:"The scrotum drains to superficial inguinal nodes. This differs from the testes, which drain to lumbar nodes because of their embryological origin."},
      {id:"lym-044",difficulty:"Hard",topic:"Female reproductive lymph drainage",subtopic:"Vagina",question:"Which vaginal lymph drainage pattern is correct?",options:{A:"Superior segment → external iliac nodes; middle segment → internal iliac nodes; inferior segment/external orifice → superficial inguinal nodes",B:"All segments drain only to lumbar lymph nodes.",C:"Superior segment drains to popliteal nodes; middle segment drains to axillary nodes.",D:"Inferior segment drains directly into the cisterna chyli."},correct:"A",explanation:"The superior vagina drains to external iliac nodes, the middle vagina to internal iliac nodes, and the inferior vagina/external orifice to superficial inguinal nodes."},
      {id:"lym-045",difficulty:"Hard",topic:"Female reproductive lymph drainage",subtopic:"Uterus",question:"Which uterine lymph drainage pairing is correct?",options:{A:"Cervix → occipital nodes",B:"Fundus → superficial inguinal lymph nodes",C:"Body → popliteal lymph nodes",D:"Fundus → bronchopulmonary lymph nodes"},correct:"B",explanation:"The uterine fundus drains to superficial inguinal nodes, the body to external iliac nodes, and the cervix to internal iliac nodes."},
      {id:"lym-046",difficulty:"Medium",topic:"Female reproductive lymph drainage",subtopic:"Ovaries and tubes",question:"Where do the ovaries primarily drain lymph?",options:{A:"Right or left lumbar lymph nodes",B:"Superficial cervical lymph nodes",C:"Parotid lymph nodes",D:"Pectoral lymph nodes"},correct:"A",explanation:"The ovaries drain to the right or left lumbar lymph nodes. The fallopian tubes drain to lumbar and internal iliac nodes."},
      {id:"lym-047",difficulty:"Hard",topic:"Upper limb lymphatics",subtopic:"Superficial vessels",question:"Which statement correctly describes superficial lymphatic drainage of the upper limb?",options:{A:"Vessels near the basilic vein enter cubital nodes and then humeral nodes; vessels near the cephalic vein enter apical axillary or deltopectoral nodes.",B:"All superficial vessels enter directly into the cisterna chyli.",C:"Superficial vessels of the upper limb drain first to popliteal nodes.",D:"Superficial lymphatics of the upper limb do not follow veins."},correct:"A",explanation:"Superficial upper limb lymphatics travel with superficial veins: basilic-associated vessels enter cubital then humeral nodes, while cephalic-associated vessels enter apical axillary or deltopectoral nodes."},
      {id:"lym-048",difficulty:"Hard",topic:"Axillary lymph nodes",subtopic:"Groups",question:"Which axillary lymph node group receives most lymph from the upper limb?",options:{A:"Pectoral nodes",B:"Subscapular nodes",C:"Humeral/lateral nodes",D:"Parasternal nodes"},correct:"C",explanation:"The humeral, or lateral, axillary lymph nodes receive most lymph drained from the upper limb."},
      {id:"lym-049",difficulty:"Hard",topic:"Axillary lymph nodes",subtopic:"Efferent drainage",question:"Which pathway correctly describes efferent lymph drainage from the apical axillary nodes?",options:{A:"Apical nodes → cervico-axillary canal → subclavian lymphatic trunk",B:"Apical nodes → popliteal nodes → lumbar trunks",C:"Apical nodes → celiac nodes → intestinal trunk",D:"Apical nodes → splenic vein → portal vein"},correct:"A",explanation:"Efferent vessels from the apical axillary nodes pass through the cervico-axillary canal and converge to form the subclavian lymphatic trunk."},
      {id:"lym-050",difficulty:"Hard",topic:"Lower limb lymphatics",subtopic:"Superficial and deep vessels",question:"Which statement correctly describes lymphatic drainage of the lower limb?",options:{A:"Medial superficial vessels ascend with the great saphenous vein to sub-inguinal nodes, while lateral superficial vessels ascend with the small saphenous vein to popliteal nodes or join the medial group.",B:"All lower limb lymph drains first to axillary apical nodes.",C:"Deep lymphatic vessels of the lower limb follow superficial veins only and avoid popliteal nodes.",D:"The lower limb drains directly into the right lymphatic duct without lymph nodes."},correct:"A",explanation:"Medial superficial vessels from the dorsum of the foot ascend with the great saphenous vein to sub-inguinal nodes. Lateral vessels ascend with the small saphenous vein and drain to popliteal nodes or join the medial group."},
    ]},
  ];
})();